/*
VS Code MSSQL extension runner (pure T-SQL)

The VS Code MSSQL extension does NOT support SQLCMD directives like :setvar / :r.
This script is self-contained: it loads @itemsJson, then runs the NAACCR->OMOP concept loader.

Input format: a JSON array like tmp/naaccr_items_example.json (but can contain many elements).
*/

SET NOCOUNT ON;
SET XACT_ABORT ON;

DECLARE @itemsJson NVARCHAR(MAX) = NULL;

/*
Option A (most portable): paste JSON directly (works everywhere, not great for huge files)

IMPORTANT:
- This file is pure T-SQL. A SQL string literal is delimited by single quotes, so any apostrophe inside
  an inline JSON payload must be doubled as `''`.
- If your JSON contains sequences like `\'` (backslash-apostrophe), that is NOT valid escaping for
  T-SQL (and is not required for JSON strings anyway). It will terminate the SQL string early and
  cause a syntax error like the one you hit.
- Recommendation: prefer Option B (load JSON from a file) to avoid all quoting/escaping issues.

*/

SET @itemsJson = N'[
