    "item_data_type": "text",
    "item_length": "9",
    "xml_naaccr_id": "addrAtDxPostalCode",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Demographic",
    "source_of_standard": "CoC",
    "date_created": "2011-11-09T14:47:21Z",
    "date_modified": "2023-05-11T14:20:30.353435Z",
    "description": "Identifies the postal code of the patient’s address at diagnosis. For consolidated records, postal code may be based on reported or corrected residential address information.",
    "rationale": "The postal code is part of the patient’s demographic data and has multiple uses. It can be used to evaluate referral patterns, allows for the analysis of cancer cluster concerns, and supports epidemiological studies that use area-based social measures.\r\n\r\n**Instructions for Coding**\r\n\r\n*   This field is intended to store ZIP Code or other postal code for the patient''s physical, residential address. The postal code for PO Box mailing address should not be entered into this data item except in the infrequent case when no other address information is available.\r\n*   If the patient has multiple tumors, the postal code at diagnosis may be different for each tumor.\r\n*   Do not update this item if the patient''s residential address changes. Store address update information in the affiliated current address data items. Only update based on improved information on the residential address at time of diagnosis. For instance, it is appropriate to correct a ZIP Code during the geocoding or consolidation process.\r\n*   For U.S. residents, use either the 5-digit or the extended 9-digit ZIP code. Blanks follow the 5-digit code if the 4-digit extension is not collected.\r\n*   For Canadian residents, use the 6-character alphanumeric postal code.\r\n*   When available, enter the postal code for other countries for out-of-country addresses.",
    "npcr_collect": "Required",
    "coc_collect": "Required",
    "seer_collect": "Required",
    "cccr_collect": "Required, when available",
    "alternate_names": [
      "Zip Code (pre-CoC)",
      "Postal Code (CCCR)",
      "Postal Code at Diagnosis (CoC)"
    ],
    "format": "Numbers or upper case letters. No special characters or embedded spaces allowed. Left justified, blank filled",
    "code_description": "In addition to known US and Canadian or other postal codes",
    "allowable_values": "5-digit or 9-digit U.S. ZIP codes; 6-character Canadian postal codes; valid postal codes from other countries, 888888888, 999999999, 88888+4 blanks (U.S.), 99999+4 blanks (U.S.), 999999+3 blanks (Canada)",
    "allowed_codes": [
      {
        "code": "888888888",
        "description": "Resident of country other than the United States, U.S. possessions or territories, or Canada and the postal code is unknown"
      },
      {
        "code": "999999999",
        "description": "Resident of the United States (including its possessions, etc.) and the postal code is unknown"
      },
      {
        "code": "999999",
        "description": "Resident of Canada and postal code is unknown"
      }
    ]
  },
