    "item_number": "80",
    "item_name": "Addr at DX--State",
    "item_data_type": "alpha",
    "item_length": "2",
    "year_implemented": "2011",
    "version_implemented": "12.2",
    "xml_naaccr_id": "addrAtDxState",
    "xml_parent_id": "Tumor",
    "record_types": [
