    "date_created": "2017-11-14T16:43:21Z",
    "date_modified": "2022-05-27T07:24:12Z",
    "description": "Adenopathy is defined as the presence of lymph nodes greater than 1.5 cm on physical examination (PE) and is part of the staging criteria for Chronic Lymphocytic Leukemia/Small Lymphocytic Lymphoma (CLL/SLL).",
    "rationale": "Adenopathy is a prognostic factor required for staging of Chronic Lymphocytic Leukemia/Small Lymphocytic Lymphoma (CLL/SLL) in AJCC 8th edition, Chapter 79, *Hodgkin and Non-Hodgkin Lymphomas*.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "Required, site specific; when available",
    "alternate_names": [
      "RAI Classification: Adenopathy"
    ],
    "code_note": "Each Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "0, 1, 5, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Adenopathy not identified/not present  \n No lymph nodes >1.5 cm  \n Physician states Rai Stage 0"
      },
      {
        "code": "1",
        "description": "Adenopathy present  \n Presence of lymph nodes >1.5 cm  \n Physician stated Rai Stage I"
      },
      {
        "code": "5",
        "description": "Not applicable: Primary site is not C421"
      },
      {
        "code": "9",
        "description": "Not documented in medical record  \n Adenopathy not assessed or unknown if assessed  \n No Rai stage is documented in the record and there is no documentation of adenopathy  \n Physician states Rai stage II-IV and there is no documentation of adenopathy"
      }
    ]
  },
