    "item_number": "2156",
    "item_name": "AJCC API Version Current",
    "item_data_type": "text",
    "item_length": "8",
    "year_implemented": "2021",
    "version_implemented": "21",
    "xml_naaccr_id": "ajccApiVersionCurrent",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Edit Overrides/Conversion History/System Admin",
    "source_of_standard": "AJCC",
    "date_created": "2020-04-29T03:23:38Z",
    "date_modified": "2022-05-27T07:24:05Z",
    "description": "This item indicates the version of the AJCC TNM API incorporated into the cancer registry software that created the record with TNM staging data in the 8th and later versions. It should be recorded the first time the AJCC Release ID (including a value of 08.01.00) is determined and should be updated each time the related input fields listed below are modified. If the registry software incorporates the AJCC API directly, the value is obtained from AJCC’s API.  If the software instead incorporates AJCC’s Cancer Surveillance API, the value can be returned from there. The value indicates the most recent time at least one of the related input items listed below was modified.  \n   \nA valid value is required for all cases diagnosed 2018 or later that have values entered in the AJCC or related data items. Cases abstracted prior to implementation of this data item will be assigned a value of 08.XX.XX during the conversion to v21.",
    "rationale": "Over time the definitions and other content contained in the AJCC’s API may change. This value indicates the most recent release used to modify at least one of the related input items listed below.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Derived",
    "seer_collect": "Derived, when available",
    "cccr_collect": "Required, when available",
    "format": "Characters may be alphanumeric and include decimal points.",
    "code_note": "*Note:* This data item will be generated by registry software. Blank is allowable in the case that no AJCC or related input items are coded.",
    "allowable_values": "Values of the form XX.YY.ZZ, Blank"
  },
  {
    "item_number": "2157",
    "item_name": "AJCC API Version Original",
    "item_data_type": "text",
    "item_length": "8",
    "year_implemented": "2021",
    "version_implemented": "21",
    "xml_naaccr_id": "ajccApiVersionOriginal",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
