    "item_name": "ALK Rearrangement",
    "item_data_type": "text",
    "item_length": "1",
    "year_implemented": "2021",
    "version_implemented": "21",
    "xml_naaccr_id": "alkRearrangement",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2020-04-29T02:42:12Z",
    "date_modified": "2022-05-27T07:24:12Z",
    "description": "Testing for ALK rearrangement is performed for patients with advanced non-small cell lung cancer (NSCLC) to identify tumors which are sensitive to small-molecule ALK kinase inhibitors.",
    "rationale": "ALK rearrangement is recommended by treatment guidelines for patients with advanced lung cancer as a prognostic marker and factor in determining appropriate therapy. It is a new data item for cases diagnosed 01/01/2021+.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required",
    "cccr_collect": "No recommendation",
    "code_note": "Each Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "0-2, 4, 7-9, Blank",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Normal  \n ALK negative  \n Negative for rearrangement, no rearrangement identified, no mutations (somatic) identified, not present, not detected"
      },
      {
        "code": "1",
        "description": "Abnormal Rearrangement identified/detected: EML4-ALK, KIF5B-ALK, TFG-ALK, and/or KLC1-ALK"
      },
      {
        "code": "2",
        "description": "Rearrangement identified/detected: Other ALK Rearrangement not listed in code 1"
      },
      {
        "code": "4",
        "description": "Rearrangement, NOS"
      },
      {
        "code": "7",
        "description": "Test ordered, results not in chart"
      },
      {
        "code": "8",
        "description": "Not applicable: Information not collected for this case  \n If this information is required by your standard setter, use of code 8 may result in an edit error."
      },
      {
        "code": "9",
        "description": "Not documented in medical record  \n ALK Rearrangement not assessed or unknown if assessed"
      },
      {
        "code": "Blank",
        "description": "Diagnosis year is prior to 2021"
      }
    ]
  },
  {
    "item_number": "442",
    "item_name": "Ambiguous Terminology DX",
    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "2006",
    "version_implemented": "11",
    "xml_naaccr_id": "ambiguousTerminologyDx",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Cancer Identification",
    "source_of_standard": "SEER",
    "date_created": "2011-11-09T14:47:21Z",
    "date_modified": "2023-09-13T09:32:52.029663Z",
    "description": "Identifies all cases, including death certificate only and autopsy only, for which an ambiguous term is the most definitive word or phrase used to establish a cancer diagnosis (i.e., to determine whether or not the case is reportable). Ambiguous terminology may originate from any source document, such as pathology report, radiology report, or from a clinical report. This data item is used only when ambiguous terminology is used to establish diagnosis. It is not used when ambiguous terminology is used to clarify a primary site, specific histology, histologic group, or stage of disease.",
    "rationale": "Cases with a reportable cancer diagnosis that has been established based only on reports that contain ambiguous terminology to describe final diagnostic findings cannot currently be identified. Multiple surveys have identified a lack of consensus in the interpretation and use of ambiguous terms across physician specialties. These cases may or may not have an actual cancer diagnosis based on clinician, radiologist, and pathologist review. Furthermore, the historical interpretation and use of ambiguous terms by cancer registrars and registries has not been consistent or compatible with physician use of these terms.\r\n\r\nThis data item will identify specific primary sites where the ambiguous terminology is commonly used to describe or establish a cancer diagnosis. Data collected will be used as the basis for modifications to case inclusion and reportable rules following complete analysis and impact assessment. This data item will allow cases to be identified within an analysis file and be excluded from patient contact studies.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Historically collected and currently transmitted",
    "seer_collect": "Historically collected and currently transmitted",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "Ambiguous Terminology",
      "Ambiguous Terminology as Basis for Diagnosis"
    ],
    "code_note": "Refer to [**Ambiguous Terms Diagnostic of Cancer**](https://apps.naaccr.org/data-dictionary/data-dictionary/version=24/chapter-view/standards-for-tumor-inclusion-and-reportability/ambiguous-terminology/)",
    "code_description": "Refer to <http://seer.cancer.gov/tools/mphrules/index.html\\> for additional instructions.",
    "allowable_values": "0-2, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Conclusive term"
      },
      {
        "code": "1",
        "description": "Ambiguous term only"
      },
      {
        "code": "2",
        "description": "Ambiguous term followed by conclusive term"
      },
      {
        "code": "9",
        "description": "Unknown term"
      }
    ]
  },
  {
    "item_number": "3811",
    "item_name": "Anemia",
    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "2018",
    "version_implemented": "18",
    "xml_naaccr_id": "anemia",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2017-11-14T16:49:28Z",
    "date_modified": "2022-05-27T07:24:09Z",
    "description": "Anemia is defined by a deficiency of red blood cells or of hemoglobin in the blood. In staging of Chronic Lymphocytic Leukemia/Small Lymphocytic Leukemia (CLL/SLL), anemia is defined as Hgb less than 11.0 g/dL.",
    "rationale": "Anemia is a prognostic factor required for staging of Chronic Lymphocytic Leukemia/Small Lymphocytic Lymphoma (CLL/SLL) in AJCC 8th edition, Chapter 79, *Hodgkin and Non-Hodgkin Lymphomas*.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
