    "allowable_values": "0, 1, 8, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "No B symptoms (asymptomatic)  \n Classified as \"A\" by physician when asymptomatic"
      },
      {
        "code": "1",
        "description": "Any B symptom(s)  \n Night sweats (drenching)  \n Unexplained fever (above 38 degrees C)  \n Unexplained weight loss (generally greater than 10% of body weight in the six months before admission)  \n B symptoms, NOS  \n Classified as \"B\" by physician when symptomatic"
      },
      {
        "code": "8",
        "description": "Not applicable: Information not collected for this case  \n (If this item is required by your standard setter, use of code 8 will result in an edit error.)"
      },
      {
        "code": "9",
        "description": "Not documented in medical record  \n B symptoms not assessed or unknown if assessed"
      }
    ]
  },
