    "item_data_type": "numeric",
    "item_length": "1",
    "year_implemented": "2024",
    "version_implemented": "24",
    "xml_naaccr_id": "brainPrimaryTumorLocation",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
