    "section": "Stage/Prognostic Factors",
    "source_of_standard": "SEER",
    "date_created": "2023-06-23T06:28:17.636475Z",
    "date_modified": "2024-07-04T01:53:15.425667Z",
    "description": "The Pons and other subsites of the Brain Stem have the same ICD-O topography code (C717), which is for subsites of the Brain Stem. Clinically, information regarding the Pons is very important, especially for pediatric cases. A schema discriminator is necessary to distinguish between the pons and other subsites of the brain stem.",
    "rationale": "The pons site is the third most common site for pediatric brain tumors and there is currently no way to identify tumors that occur in this site. Surgery is too dangerous for these types of tumors. Needle biopsies are also dangerous and extremely rare. Without pathology specimens, accurate histology is elusive making accurate incidence not possible. A cascade of implications results without accurate incidence including support for drug development.",
    "npcr_collect": "Required, site specific",
    "coc_collect": "Required",
    "seer_collect": "Required, site specific",
    "cccr_collect": "Required, site specific; when available",
    "code_note": "**Note 1:** This SSDI is effective for diagnosis years 2024+\r\n\r\n*   For cases diagnosed 2018-2023, leave this SSDI blank",
    "allowable_values": "1, 2, 8, 9, Blank",
    "allowed_codes": [
      {
        "code": "1",
        "description": "Pons"
      },
      {
        "code": "2",
        "description": "Subsite other than Pons\r\n\r\n*   Basis peduncle\r\n*   Cerebral peduncle\r\n*   Choroid plexus of fourth ventricle\r\n*   Fourth ventricle, NOS\r\n*   Infratentorial brain, NOS\r\n*   Medulla oblongata\r\n*   Midbrain\r\n*   Olive\r\n*   Pyramid"
      },
      {
        "code": "8",
        "description": "Information not collected for this case"
      },
      {
        "code": "9",
        "description": "Brain stem, NOS\r\n\r\nUnknown subsite of Brain Stem"
      }
    ]
  },
