    ],
    "format": "4 digits (for ICD-7, 8, 9); for ICD-10,  upper case letter followed by 3 digits or upper case letter followed by 2 digits plus blank",
    "code_description": "Special codes in addition to ICD-7, ICD-8, ICD-9, and ICD-10 (refer to *[SEER Program Code Manual](http://seer.cancer.gov/tools/codingmanuals/)* for additional instructions.)",
    "allowable_values": "Valid ICD-7, ICD-8, ICD-9, and ICD-10 codes; also 0000, 7777, 7797",
    "allowed_codes": [
