    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "2018",
    "version_implemented": "18",
    "xml_naaccr_id": "ceaPretreatmentInterpretation",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
