      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2017-11-14T16:56:27Z",
    "date_modified": "2022-05-27T07:24:11Z",
    "description": "CEA (Carcinoembryonic Antigen) Pretreatment Interpretation refers to the interpretation of the CEA value prior to treatment. CEA is a glycoprotein that is produced by adenocarcinomas from all sites as well as many squamous cell carcinomas of the lung and other sites. CEA may be measured in blood, plasma or serum. CEA is a prognostic marker for adenocarcinomas of the appendix, colon and rectum and is used to monitor response to treatment",
    "rationale": "CEA (Carcinoembryonic Antigen) is a Registry Data Collection Variable for AJCC 8. CEA (Carcinoembryonic Antigen) Pretreatment Interpretation was previously collected as Colon and Rectum, CS SSF #1.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "Required, site specific; when available",
    "code_note": "Each Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "0-3, 7-9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "CEA negative/normal; within normal limits"
      },
      {
        "code": "1",
        "description": "CEA positive/elevated"
      },
      {
        "code": "2",
        "description": "Borderline"
      },
      {
        "code": "3",
        "description": "Undetermined if positive or negative (normal values not available)  \n AND no MD interpretation"
      },
      {
        "code": "7",
        "description": "Test ordered, results not in chart"
      },
      {
        "code": "8",
        "description": "Not applicable: Information not collected for this case  \n (If this data item is required by your standard setter, use of code 8 will result in an edit error.)"
      },
      {
        "code": "9",
        "description": "Not documented in medical record  \n CEA (Carcinoembryonic Antigen) Pretreatment Interpretation not assessed or unknown if assessed"
      }
    ]
  },
