  {
    "item_number": "120",
    "item_name": "Census Cod Sys 1970/80/90",
    "item_data_type": "digits",
    "item_length": "1",
    "xml_naaccr_id": "censusCodSys19708090",
    "xml_parent_id": "Tumor",
    "record_types": [
