  {
    "item_number": "3823",
    "item_name": "Circumferential Resection Margin (CRM)",
    "item_data_type": "text",
    "item_length": "4",
    "year_implemented": "2018",
    "version_implemented": "18",
    "xml_naaccr_id": "circumferentialResectionMargin",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2017-11-15T08:00:03Z",
    "date_modified": "2023-06-29T11:11:41.635859Z",
    "description": "Circumferential or Radial Resection Margin, the distance in millimeters between the leading edge of the tumor and the surgically dissected margin as recorded on the pathology report, is a prognostic indicator for colon and rectal cancer. This may also be referred to as the Radial Resection Margin or surgical clearance.",
    "rationale": "Circumferential or Radial Resection Margin is a Registry Data Collection Variable in AJCC. It was previously collected as Colon and Rectum CS SSF# 6.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "Required, site specific; when available",
    "code_note": "Each Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "0.0, 0.1-99.9, XX.1, XX.2, XX.3, XX.4, XX.5, XX.6, XX.7, XX.8, XX.9",
    "allowed_codes": [
      {
        "code": "0.0",
        "description": "Circumferential resection margin (CRM) positive  \n Margin IS involved with tumor  \n Described as \"less than 1 millimeter (mm)\""
      },
      {
        "code": "0.1-99.9",
        "description": "Distance of tumor from margin: 0.1- 99.9 millimeters (mm)  \n (Exact size to nearest tenth of millimeter)"
      },
      {
        "code": "XX.0",
        "description": "100 mm or greater"
      },
      {
        "code": "XX.1",
        "description": "Margins clear, distance from tumor not stated  \n Circumferential or radial resection margin negative, NOS  \n No residual tumor identified on specimen"
      },
      {
        "code": "XX.2",
        "description": "Margins cannot be assessed"
      },
      {
        "code": "XX.3",
        "description": "Described as \"at least\" 1 mm"
      },
      {
        "code": "XX.4",
        "description": "Described as \"at least\" 2 mm"
      },
      {
        "code": "XX.5",
        "description": "Described as \"at least\" 3 mm"
      },
      {
        "code": "XX.6",
        "description": "Described as \"greater than\" 3 mm"
      },
      {
        "code": "XX.7",
        "description": "No resection of primary site  \n Surgical procedure did not remove enough tissue to measure the circumferential or radial resection margin  \n (Examples include: polypectomy only, endoscopic mucosal resection (EMR), excisional biopsy only, transanal disk excision)"
      },
      {
        "code": "XX.8",
        "description": "Not applicable: Information not collected for this case  \n (If this information is required by your standard setter, use of code XX.8 may result in an edit error.)"
      },
      {
        "code": "XX.9",
        "description": "Not documented in medical record  \n Circumferential or radial resection margin not assessed or unknown if assessed"
      }
    ]
  },
  {
    "item_number": "610",
    "item_name": "Class of Case",
    "item_data_type": "digits",
    "item_length": "2",
    "year_implemented": "1990",
    "version_implemented": "pre V4",
    "xml_naaccr_id": "classOfCase",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Hospital-Specific",
    "source_of_standard": "CoC",
    "date_created": "2011-11-10T05:47:21Z",
    "date_modified": "2024-09-09T22:36:07.581642Z",
    "description": "Class of Case divides cases into two groups. Analytic cases (codes 00-22) are those that are required by CoC to be abstracted because of the program’s primary responsibility in managing the cancer. Analytic cases are grouped according to the location of diagnosis and treatment. Treatment and outcome reports may be limited to analytic cases. Nonanalytic cases (codes 30-49 and 99) may be abstracted by the facility to meet central registry requirements or because of a request by the facility’s cancer program. Nonanalytic cases are grouped according to the reason a patient who received care at the facility is nonanalytic, or the reason a patient who never received care at the facility may have been abstracted.\r\n\r\nClass of Case can be used in conjunction with Type of Reporting Source \\[500\\]. Type of Reporting Source is designed to document the source of documents used to abstract the cancer being reported.",
    "general_notes": "_Note:_ This expanded list of coded values is effective with Version 12. \\*Indicates Class of Case codes appropriate for abstracting cases from non-hospital sources such as physician offices, ambulatory surgery centers, freestanding pathology laboratories, radiation therapy centers. When applied to these types of facilities, the non-hospital source is the reporting facility. The codes are applied the same way as if the case were reported from a hospital. By using Class of Case codes in this manner for non-hospital sources, the central cancer registry is able to retain information reflecting the facility’s role in managing the cancer consistent with the way it is reported from hospitals. Using Class of Case in conjunction with Type of Reporting Source \\[500\\] which identifies the source documents used to abstract the cancer being reported, the central cancer registry has two distinct types of information to use in making consolidation decisions",
    "rationale": "Class of Case reflects the facility''s role in managing the cancer, whether the cancer is required to be reported by CoC, and whether the case was diagnosed after the program''s Reference Date.",
    "npcr_collect": "Required",
    "coc_collect": "Required",
    "seer_collect": "Required",
    "cccr_collect": "No recommendation",
    "format": "Right justified, zero filled",
    "code_note": "_Note:_ This expanded list of coded values is effective with Version 12.\r\n\r\n\\*Indicates Class of Case codes appropriate for abstracting cases from non-hospital sources such as physician offices, ambulatory surgery centers, freestanding pathology laboratories, radiation therapy centers. When applied to these types of facilities, the non-hospital source is the reporting facility. The codes are applied the same way as if the case were reported from a hospital.\r\n\r\nBy using Class of Case codes in this manner for non-hospital sources, the central cancer registry is able to retain information reflecting the facility''s role in managing the cancer consistent with the way it is reported from hospitals. Using Class of Case in conjunction with Type of Reporting Source \\[500\\] which identifies the source documents used to abstract the cancer being reported, the central cancer registry has two distinct types of information to use in making consolidation decisions",
    "code_description": "Analytic Classes of Case (Required by CoC to be abstracted by accredited cancer programs; refer to [_STORE_](http://www.facs.org/cancer/coc/fordsmanual.html) for additional instructions)",
    "allowable_values": "00, 10-14, 20-22, 30-38, 40-43, 49, 99",
    "allowed_codes": [
      {
        "code": "<b>INITIAL DIAGNOSIS AT REPORTING FACILITY</b>"
      },
      {
        "code": "00*",
        "description": "Initial diagnosis at the reporting facility AND all treatment or a decision not to treat was done ELSEWHERE"
      },
      {
        "code": "10*",
        "description": "Initial diagnosis at the reporting facility or in a staff physician''s office AND PART OR ALL of first course treatment or a decision not to treat was at the reporting facility, NOS"
      },
      {
        "code": "11",
        "description": "Initial diagnosis in staff physician''s office AND PART of first course treatment was done at the reporting facility"
      },
      {
        "code": "12",
        "description": "Initial diagnosis in staff physician''s office AND ALL first course treatment or a decision not to treat was done at the reporting facility"
      },
      {
        "code": "13*",
        "description": "Initial diagnosis at the reporting facility AND PART of first course treatment was done at the reporting facility"
      },
      {
        "code": "14*",
        "description": "Initial diagnosis at the reporting facility AND ALL first course treatment or a decision not to treat was done at the reporting facility"
      },
      {
        "code": "<b>INITIAL DIAGNOSIS ELSEWHERE, FACILITY INVOLVED IN FIRST COURSE TREATMENT</b>"
      },
      {
        "code": "20*",
        "description": "Initial diagnosis elsewhere AND PART OR ALL of first course treatment was done at the reporting facility, NOS"
      },
      {
        "code": "21*",
        "description": "Initial diagnosis elsewhere AND PART of treatment was done at the reporting facility"
      },
      {
        "code": "22*",
        "description": "Initial diagnosis elsewhere AND ALL first course treatment was done at the reporting facility"
      },
      {
        "code": "<b>Classes of Case not required by CoC to be abstracted (May be required by Cancer Committee, state or regional registry, or other entity)</b>"
      },
      {
        "code": "<b>PATIENT APPEARS IN PERSON AT REPORTING FACILITY; BOTH INITIAL DIAGNOSIS AND TREATMENT ELSEWHERE</b>"
      },
      {
        "code": "30*",
        "description": "Initial diagnosis and all first course treatment elsewhere AND reporting facility participated in DIAGNOSTIC WORKUP (for example, consult only, staging workup after initial diagnosis elsewhere)"
      },
      {
        "code": "31*",
        "description": "Initial diagnosis and all first course treatment elsewhere AND reporting facility provided IN-TRANSIT care"
      },
      {
        "code": "32*",
        "description": "Diagnosis AND all first course treatment provided elsewhere AND patient presents at reporting facility with disease RECURRENCE OR PERSISTENCE"
      },
      {
        "code": "33*",
        "description": "Diagnosis AND all first course treatment provided elsewhere AND patient presents at reporting facility with disease HISTORY ONLY"
      },
      {
        "code": "34",
        "description": "Type of case not required by CoC to be accessioned (for example, a benign colon tumor) AND initial diagnosis AND part or all of first course treatment by reporting facility"
      },
      {
        "code": "35",
        "description": "Case diagnosed before program''s Reference Date AND initial diagnosis AND PART OR ALL of first course treatment by reporting facility"
      },
      {
        "code": "36",
        "description": "Type of case not required by CoC to be accessioned (for example, a benign colon tumor) AND initial diagnosis elsewhere AND part or all of first course treatment by reporting facility"
      },
      {
        "code": "37",
        "description": "Case diagnosed before program''s Reference Date AND initial diagnosis elsewhere AND all or part of first course treatment by reporting facility"
      },
      {
        "code": "38*",
        "description": "Initial diagnosis established by AUTOPSY at the reporting facility, cancer not suspected prior to death"
      },
      {
        "code": "<b>PATIENT DOES NOT APPEAR IN PERSON AT REPORTING FACILITY</b>"
      },
      {
        "code": "40",
        "description": "Diagnosis AND all first course treatment given at the same staff physician''s office"
      },
      {
        "code": "41",
        "description": "Diagnosis and all first course treatment given in two or more different staff physician offices"
      },
      {
        "code": "42",
        "description": "Non-staff physician or non-CoC accredited clinic or other facility, not part of reporting facility, accessioned by reporting facility for diagnosis and/or treatment by that entity (for example, hospital abstracts cases from an independent radiation facility)"
      },
      {
        "code": "43*",
        "description": "PATHOLOGY or other lab specimens ONLY"
      },
      {
        "code": "49*",
        "description": "DEATH CERTIFICATE ONLY"
      },
      {
        "code": "<b>UNKNOWN RELATIONSHIP TO REPORTING FACILITY</b>"
      },
      {
        "code": "99*",
        "description": "Nonanalytic case of unknown relationship to facility (not for use by CoC accredited cancer programs for analytic cases.); UNKNOWN"
      }
    ]
  },
