    "item_number": "3961",
    "item_name": "Clinical Margin Width",
    "item_data_type": "text",
    "item_length": "4",
    "year_implemented": "2023",
    "version_implemented": "2023",
    "xml_naaccr_id": "clinicalMarginWidth",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "CoC",
    "date_created": "2022-06-23T19:05:45Z",
    "date_modified": "2023-07-06T17:10:18.490131Z",
    "description": "Clinical Margin Width describes the margins from a wide excision for a melanoma primary. The margin width is measured by the surgeon prior to the procedure. The measurement is taken, in centimeters, from the edge of the lesion or the prior excision scar to the peripheral margin of the specimen.",
    "rationale": "Clinical margin width for wide local excision of a melanoma is based on the original Breslow thickness of the primary tumor, as indicated on the initial biopsy pathology report.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "No recommendation",
    "allowable_values": "0.1, 0.2-9.9, XX.1, XX.8"
  },
  {
    "item_number": "2152",
    "item_name": "CoC Accredited Flag",
    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "2018",
    "version_implemented": "18",
    "xml_naaccr_id": "cocAccreditedFlag",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Edit Overrides/Conversion History/System Admin",
    "source_of_standard": "NPCR",
    "date_created": "2017-11-14T16:15:29Z",
    "date_modified": "2022-05-27T07:24:13Z",
    "description": "CoC Accredited Flag is assigned at the point and time of data abstraction to label an abstract being prepared for an analytic cancer case at a facility accredited by the Commission on Cancer (CoC). The flag may be assigned manually or can be defaulted by the registry’s software.",
    "rationale": "CoC-accredited facilities are required to collect certain data items including TNM staging. It is burdensome for central registries to maintain a list of accredited facilities, and the list changes frequently. The flag is a means of incorporating the accredited status into abstracts at the time of abstraction by someone who has knowledge of the status. The flag thus simplifies validating that required items have been abstracted by CoC-accredited facilities. The flag also allows cases to be stratified during analyses to identify those never seen at a CoC-accredited facility; e.g., percentage of all cases seen in at least one CoC-accredited facility, evaluation of outcomes by facility status. NPCR will use this flag for facility status stratification.",
    "npcr_collect": "Required",
    "coc_collect": "No recommendation",
    "seer_collect": "Required",
    "cccr_collect": "No recommendation",
    "allowable_values": "0, 1, 2, Blank",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Abstract prepared at a facility WITHOUT CoC accreditation of its cancer program"
      },
      {
        "code": "1",
        "description": "ANALYTIC abstract prepared at facility WITH CoC accreditation of its cancer program (Includes Class of Case codes 10-22)"
      },
      {
        "code": "2",
        "description": "NON-ANALYTIC abstract prepared at facility WITH CoC accreditation of its cancer program (Includes Class of Case codes 30-43 and 99, plus code 00 which CoC considers analytic but does not require to be staged)"
      },
      {
        "code": "Blank",
        "description": "Not applicable; DCO"
      }
    ]
  },
