  {
    "item_number": "200",
    "item_name": "Computed Ethnicity",
    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "1995",
    "version_implemented": "4",
    "xml_naaccr_id": "computedEthnicity",
    "xml_parent_id": "Patient",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Demographic",
    "source_of_standard": "SEER",
    "date_created": "2011-11-09T09:47:21Z",
    "date_modified": "2022-05-27T07:24:13Z",
    "description": "Code identifying those cases for which ethnicity was determined by matching Name--Last [2230] and Name--Maiden [2390] to a computer list of Spanish/Hispanic names or by a software algorithm. This field was adopted for use for tumors diagnosed 1994 forward. See also Computed Ethnicity Source [210].",
    "rationale": "One method of identifying persons of Hispanic origin is to apply a standard computer list or algorithm to items 2230 and 2390, the patient’s surname and/or maiden name. This has advantages across large populations of being reproducible and facilitating comparisons between areas using identical methods. It may sometimes be possible to identify population denominators in which the same method was used to identify Hispanics. Generally, only central registries will have this capability.  \n  \nThis field provides coding to indicate both that such a computerized name-based method was applied and the results of the method. Coding is independent of that in Spanish/Hispanic Origin [190]. The computer-derived ethnicity may be different from the ethnicity reported by registries in Spanish/Hispanic Origin [190] as code 7 (Spanish Surname Only), because that field may include manual review. This field shows the results of computer-derived ethnicity only.",
    "npcr_collect": "No recommendation",
    "coc_collect": "No recommendation",
    "seer_collect": "Derived",
    "cccr_collect": "No recommendation",
    "code_note": " *Note:* For SEER, blanks are required for all cases diagnosed before 1994 and blanks are not allowed for any case diagnosed 1994 and after. Other registries may have computed this item for earlier years. *Note:* NAACCR recognizes that available definitions and abstracting instructions for the data items Name--Last and Name--Maiden may be inadequate for describing names used in some cultures, including Hispanic cultures. Explicit instructions have not been provided for entering compound names, with or without hyphens or “De.” Order of names, use of maternal and paternal names, and use of hyphens can vary across cultures. It is likely, too, that abstracting and coding practice for these items varies across registries. Limitations inherent in these definitions should be kept in mind in any use of the data.",
    "allowable_values": "0-7, blank",
    "allowed_codes": [
      {
        "code": "0",
        "description": "No match was run (for 1994 and later tumors)"
      },
      {
        "code": "1",
        "description": "Non-Hispanic last name and non-Hispanic maiden name"
      },
      {
        "code": "2",
        "description": "Non-Hispanic last name, did not check maiden name or patient was male"
      },
      {
        "code": "3",
        "description": "Non-Hispanic last name, missing maiden name"
      },
      {
        "code": "4",
        "description": "Hispanic last name, non-Hispanic maiden name"
      },
      {
        "code": "5",
        "description": "Hispanic last name, did not check maiden name or patient was male"
      },
      {
        "code": "6",
