    ],
    "section": "Treatment-1st Course",
    "source_of_standard": "CoC",
    "date_created": "2012-04-04T09:04:56Z",
    "date_modified": "2023-09-15T07:38:06.76628Z",
    "description": "Date of initiation of the first therapy for the cancer being reported, using the CoC definition of first course. The date of first treatment includes the date a decision was made not to treat the patient. See _STORE_ for details. See Chapter V, Unresolved Issues for further discussion of the difference between SEER and CoC items. See [**Data Descriptor Table**](https://apps.naaccr.org/data-dictionary/data-dictionary/version=24/chapter-view/data-descriptor-table/) for date format.   \r\n   \r\nFormerly Date of 1st Crs RX--CoC.",
    "clarification": "**Clarification of NPCR Required Status**\r\n\r\nCentral registries funded by NPCR are required to collect either Date Initial RX SEER \\[1260\\] or Date 1st Crs RX CoC \\[1270\\].",
    "npcr_collect": "R#*",
    "coc_collect": "Required",
    "seer_collect": "No recommendation",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "Date Started (pre 96 CoC)",
      "Date of First Course Treatment (CoC)",
      "Date of 1st Crs RX--CoC"
    ],
    "format": "YYYYMMDD",
    "allowable_values": "Valid dates"
  },
  {
    "item_number": "2090",
