    "section": "Edit Overrides/Conversion History/System Admin",
    "source_of_standard": "NAACCR",
    "date_created": "2011-11-09T14:47:21Z",
    "date_modified": "2023-09-15T07:04:49.277575Z",
    "description": "The date that: (1) the abstractor decided that the tumor report was complete and (2) the case passed all edits that were applied. Definitions may vary among registries and software providers. This field is locally used by central registries. See [**Data Descriptor Table**](https://apps.naaccr.org/data-dictionary/data-dictionary/version=24/chapter-view/data-descriptor-table/) for date format. Standard edits check that no dates are later than the current date. These specifications will not necessarily be the same as those used for Date Case Completed--CoC \\[2092\\].",
    "npcr_collect": "No recommendation",
    "coc_collect": "No recommendation",
    "seer_collect": "No recommendation",
    "cccr_collect": "No recommendation",
    "format": "YYYYMMDD",
    "allowable_values": "Valid date"
  },
  {
    "item_number": "2092",
    "item_name": "Date Case Completed--CoC",
    "item_data_type": "date",
