      "I",
      "M"
    ],
    "section": "Edit Overrides/Conversion History/System Admin",
    "source_of_standard": "CoC",
    "date_created": "2011-11-09T14:47:21Z",
    "date_modified": "2023-09-15T07:05:24.056374Z",
    "description": "Identifies the date that specified items are completed, based on the Class of Case, where those items pass the relevant edits. Follow-up information, including delayed treatment received elsewhere, may be coded after the Date Case Completed--CoC. See the current [_STORE_](http://www.facs.org/cancer/coc/fordsmanual.html) for details. This item should be autocoded by the registry software; specifications may be obtained from NCDB. The CoC specifications will not necessarily be the same as those used for Date Case Completed \\[2090\\]. See [**Data Descriptor Table**](https://apps.naaccr.org/data-dictionary/data-dictionary/version=24/chapter-view/data-descriptor-table/) for date format.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Derived",
    "seer_collect": "No recommendation",
    "cccr_collect": "No recommendation",
    "format": "YYYYMMDD",
    "allowable_values": "Valid date"
  },
  {
    "item_number": "2085",
    "item_name": "Date Case Initiated",
    "item_data_type": "date",
    "item_length": "8",
    "year_implemented": "2010",
    "version_implemented": "12",
    "xml_naaccr_id": "dateCaseInitiated",
    "xml_parent_id": "Tumor",
    "record_types": [
