    ],
    "section": "Cancer Identification",
    "source_of_standard": "SEER",
    "date_created": "2012-04-04T05:05:32Z",
    "date_modified": "2023-09-15T06:56:19.030879Z",
    "description": "Documents the date when a conclusive cancer diagnosis (definite statement of malignancy) is made following an initial diagnosis that was based only on ambiguous terminology. See [**Data Descriptor Table**](https://apps.naaccr.org/data-dictionary/data-dictionary/version=24/chapter-view/data-descriptor-table/) for date format. Use DATE CONCLUSIVE DX FLAG \\[448\\] if there is no appropriate or known date for this item.  \r\n   \r\nFormerly Date of Conclusive DX.",
    "rationale": "This date will allow analysis of the primary site locations and frequency of cases that were originally diagnosed by ambiguous terminology and later confirmed by other conclusive method.\r\n\r\nThis date will also allow for analysis of the time interval between cancer diagnosis based on ambiguous terminology and confirmation of the cancer diagnosis by conclusive means.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Historically collected and currently transmitted",
    "seer_collect": "Historically collected and currently transmitted",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "Date of Conclusive Diagnosis",
      "Date of Conclusive Terminology",
      "Date of Conclusive DX"
    ],
    "format": "YYYYMMDD",
    "code_description": "Refer to <http://seer.cancer.gov/tools/mphrules/index.html\\> for additional instructions",
    "allowable_values": "Valid date"
  },
  {
