    "item_number": "3955",
    "item_name": "Derived Rai Stage",
    "item_data_type": "text",
    "item_length": "1",
    "year_implemented": "2022",
    "version_implemented": "22",
    "xml_naaccr_id": "derivedRaiStage",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2021-06-07T09:32:30Z",
    "date_modified": "2023-03-28T02:14:06Z",
    "description": "This data item stores the Derived Rai stage value derived from the values coded in the following SSDIs for the Lymphoma-CLL/SLL schema (9823/3).  \n  \n  \n* Lymphocytosis [3885]\n* Adenopathy [3804]\n* Organomegaly [3907]\n* Anemia [3811]\n* Thrombocytopenia [3933]\n\nThe Rai stage is only applicable for Chronic Lymphocytic Leukemia/Small Lymphocytic Lymphoma (CLL/SLL) (9823/3) cases where the primary site is bone marrow (C421). For cases with a primary site other than bone marrow (C421), the derived Rai stage will be 8 and all the SSDIs will be coded to 5.  \n   \nDerivation will be run on all cases diagnosed 1/1/2018 and forward.",
    "general_notes": "\n\n\n",
    "rationale": "The Derived Rai stage can be used to evaluate disease spread at diagnosis, treatment patterns and outcomes over time.",
    "npcr_collect": "No recommendation",
    "coc_collect": "No recommendation",
    "seer_collect": "Derived",
    "cccr_collect": "No recommendation",
    "code_note": "This field should be left blank for all cases diagnosed prior to 2018, for schemas other than 00795, and when not required by standard setter.",
    "allowable_values": "0-4, 8, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Lymphocytosis"
      },
      {
        "code": "1",
        "description": "Lymphocytosis and Adenopathy"
      },
      {
        "code": "2",
        "description": "Lymphocytosis and Organomegaly<br/> (Adenopathy is any value other than 5)"
      },
      {
        "code": "3",
        "description": "Lymphocytosis and Anemia<br/> (Adenopathy and Organomegaly are any value other than 5)"
      },
      {
        "code": "4",
        "description": "Lymphocytosis and Thrombocytopenia<br/> (Adenopathy, Organomegaly and Anemia are any value other than 5)"
      },
      {
        "code": "8",
        "description": "Does not apply, primary site not bone marrow (C421)<br/> (All 5 SSDIs should be set to 5)"
      },
      {
        "code": "9",
        "description": "Unknown<br/> (All 5 SSDIs are 9 or blank; at least one is set to 9 OR<br/> Lymphocytosis is 0,7,9 OR<br/> Lymphocytosis is blank and one of the other SSDIs is a value other than 5 or 9)"
      }
    ]
  },
