    "npcr_collect": "Historically collected and currently transmitted when available",
    "coc_collect": "DH",
    "seer_collect": "DH",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "SS2000 Conversion Flag"
    ],
    "code_description": "See the most current version of the** **Collaborative Stage Data Collection System** **(<https://cancerstaging.org/cstage/Pages/default.aspx\\>),^13^ for rules and site-specific codes and coding structures.",
    "allowable_values": "1, 2, blank",
