        "code": "1",
        "description": "Positive histology"
      },
      {
        "code": "2",
        "description": "Positive cytology"
      },
      {
        "code": "3",
        "description": "Positive histology PLUS - positive immunophenotyping AND/OR positive genetic studies (Used only for hematopoietic and lymphoid neoplasms M-9590/3-9992/3)"
      },
      {
        "code": "4",
        "description": "Positive microscopic confirmation, method not specified"
      },
      {
        "code": "5",
        "description": "Positive laboratory test/marker study"
      },
      {
        "code": "6",
        "description": "Direct visualization without microscopic confirmation"
      },
      {
        "code": "7",
        "description": "Radiography and/or other imaging techniques without microscopic confirmation"
      },
      {
        "code": "8",
        "description": "Clinical diagnosis only (other than 5, 6, or 7)"
      },
      {
        "code": "9",
        "description": "Unknown whether or not microscopically confirmed; death certificate only"
      }
    ]
