    ],
    "section": "Demographic",
    "source_of_standard": "NPCR",
    "date_created": "2021-06-07T19:05:35Z",
    "date_modified": "2023-06-20T12:06:43.933595Z",
    "description": "EDP MDE Link identifies breast, cervical, or colorectal cancer cases in the registry database that matched the same patient and tumor in CDC’s [National Breast and Cervical Cancer Early Detection Program](https://www.cdc.gov/cancer/nbccedp/) (NBCCEDP) data set, CDC’s [Colorectal Cancer Control Program (CRCCP)](https://www.cdc.gov/cancer/crccp/) data set, or both, indicating that the cancer was identified through one or both screening programs in the registry’s state, territory, or jurisdiction. Use the EDP MDE Link variable to record results from the registry’s data linkage with the appropriate NBCCED/CRCC program(s).",
    "rationale": "This data item classifies cancers first identified through an early detection program (EDP) and allows analyses to evaluate trends, identify disparities, and evaluate program success. This linkage process can also identify cancers not reported to the central cancer registry.",
    "npcr_collect": "Required, site specific",
    "coc_collect": "No recommendation",
    "seer_collect": "No recommendation",
    "cccr_collect": "No recommendation",
    "allowable_values": "0, 1, Blank",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Breast, cervical, or colorectal cancer record sent for linkage, no match for this cancer with the Early Detection Program (EDP) data"
      },
      {
        "code": "1",
        "description": "Breast, cervical, or colorectal cancer record sent for linkage, match for this cancer with EDP data"
      },
      {
        "code": "Blank",
        "description": "Breast, cervical, or colorectal cancer record not sent for linkage, or linkage results are pending, or record not a breast, cervical, or colorectal cancer"
      }
    ]
  },
