    "coc_collect": "No recommendation",
    "seer_collect": "Required, site specific; when available",
    "cccr_collect": "No recommendation",
    "code_note": "**Note 1: Effective years**\r\n\r\n*   This SSDI is effective for diagnosis years 2024+\r\n*   For cases diagnosed 2018-2023, this SSDI must be blank\r\n\r\n**Note 2:** **Physician statement**\r\n\r\n*   Physician statement of EWSR1-FLI1 fusion can be used to code this data item when no other information is available.",
    "allowable_values": "0-5, 7-9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "No gene rearrangements (fusions) identified"
      },
      {
        "code": "1",
        "description": "EWSR1-FLI1 gene rearrangement (fusion) present"
      },
      {
        "code": "2",
        "description": "EWSR1-ERG gene rearrangement (fusion) present"
      },
      {
        "code": "3",
        "description": "Other EWSR1 gene rearrangement (fusion) present"
      },
      {
        "code": "4",
        "description": "EWSR1 rearrangement present, fusion partner not known"
      },
      {
        "code": "5",
        "description": "Non-EWSR1 variant translocation present"
      },
      {
        "code": "7",
        "description": "Test ordered, results not in chart"
      },
      {
        "code": "8",
        "description": "Not applicable: Information not collected for this case  \r\n(If this information is required by your standard setter, use of code 8 may result in an edit error.)"
