  {
    "item_number": "2440",
    "item_name": "Following Registry",
    "item_data_type": "digits",
    "item_length": "10",
    "xml_naaccr_id": "followingRegistry",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
