    ],
    "section": "Hospital-Confidential",
    "source_of_standard": "CoC",
    "date_created": "2011-11-09T09:47:21Z",
    "date_modified": "2022-05-27T07:24:06Z",
    "description": "Records the FIN of the registry responsible for following the patient.",
    "general_notes": "\n\n*Note*: This item is not supported by CoC as of January 1, 2010, (the respective NPI item is required).",
    "rationale": "The number is essential to NCDB for monitoring data submissions, ensuring the accuracy of data, and identifying areas for special studies.   \n   \n**Instructions for Coding**  \nCoC maintains the codes, including those for non-hospital sources of reporting.  \n  \nFor facilities with 7-digit FINs, consisting of a constant “6” followed by 6-digit facility-specific codes in the range of 6020009-6953290 that were assigned by CoC before January 1, 2001: Enter all FIN codes of this type as 3 zeroes, followed by the constant “6” and the 6-digit facility-specific codes.  \n  \nFor facilities with FINs greater than or equal to 10000000 that were assigned by CoC after January 1, 2001: Enter FIN codes of this type as 2 zeroes followed by the full 8-digit code. These sometimes are called CoC FIN 10-digit codes.  ",
    "npcr_collect": "No recommendation",
    "coc_collect": "No recommendation",
    "seer_collect": "Historically collected and currently transmitted",
    "cccr_collect": "No recommendation",
    "format": "Right justified and zero filled",
    "code_description": "In addition to CoC assigned codes",
    "allowable_values": "10-digit number",
    "allowed_codes": [
      {
        "code": "0000000000",
        "description": "Case not reported by a facility"
      },
      {
        "code": "0099999999",
        "description": "Case reported, but facility number is unknown"
      }
    ]
  },
