  {
    "item_number": "3856",
    "item_name": "Heritable Trait",
    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "2018",
    "version_implemented": "18",
    "xml_naaccr_id": "heritableTrait",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2017-11-14T17:28:05Z",
    "date_modified": "2022-05-27T07:24:05Z",
    "description": "Heritable trait pertains to evidence that a tumor is associated with a heritable mutation. In retinoblastoma, the heritable trait is a germline mutation in the RB1 gene, which is associated with bilateral disease, family history of retinoblastoma, presence of concomitant CNS midline embryonic tumor (commonly in pineal region), or retinoblastoma with an intracranial primitive neuroectodermal tumor (i.e., trilateral retinoblastoma). Children with any of these features may be assigned the H1 status without molecular testing. High quality molecular testing for RB1 mutation is required to determine the presence or absence of RB1 mutation for children without clinical features of a heritable mutation.",
    "clarification": "Heritable trait is required for prognostic stage grouping in AJCC 8th edition, Chapter 68 *Retinoblastoma*. It is a new data item for cases diagnosed 1/1/2018+.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "Required, site specific; when available",
    "code_note": "Each Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "0, 1, 7, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "H0: Normal RB1 alleles  \n No clinical evidence of mutation"
      },
      {
        "code": "1",
        "description": "H1: RB1 gene mutation OR  \n Clinical evidence of mutation"
      },
      {
        "code": "7",
        "description": "Test ordered, results not in chart"
      },
      {
        "code": "9",
        "description": "HX: Not documented in medical record  \n Test not done, or unknown if done  \n Insufficient evidence of a constitutional RB1 gene mutation"
      }
    ]
  },
