    "allowed_codes": [
      {
        "code": "0.0",
        "description": "0.0"
      },
      {
        "code": "0.1",
        "description": "0.1 or less"
      },
      {
        "code": "0.2-9.9",
        "description": "0.2 - 9.9  \n (Exact ratio to nearest tenth)"
      },
      {
        "code": "X.1",
        "description": "10 or greater"
      },
      {
        "code": "X.7",
        "description": "Test ordered, results not in chart"
      },
      {
