    "item_number": "1188",
    "item_name": "IRSS Stage for Eye-2",
    "item_data_type": "numeric",
    "item_length": "1",
    "year_implemented": "2025",
    "version_implemented": "25",
    "xml_naaccr_id": "irssStageForEye2",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR/SEER",
    "date_created": "2024-04-27T01:43:41.6039Z",
    "date_modified": "2024-05-30T20:55:49.320221Z",
    "description": "Bilateral retinoblastoma is abstracted as a single primary regardless of timing, but there is no effective way to measure the different extent of diseases or stages for each eye beyond text. Currently, abstractors are required to enter the information of the most advanced eye in the staging data fields, losing all measurable data on the stage the less advanced eye.\r\n\r\nThis field allows the abstractor to enter the individual stages for each eye in cases of bilateral retinoblastoma at the time of diagnosis.",
    "general_notes": "**Source documents:** imaging, pathology report, clinician’s statement",
    "rationale": "Even though staging information for only one retinoblastoma tumor can currently be captured in data form, abstractors are still required to put treatment information for bilaterally affected eyes into the treatment fields of the abstract. The ability to capture measurable staging data of the contralateral eye will provide substantiation of the treatment captured for both eyes in the abstract.",
    "npcr_collect": "No recommendation",
    "coc_collect": "No recommendation",
    "seer_collect": "Required, site specific; when available",
    "cccr_collect": "No recommendation",
    "code_note": "**Note 1: Effective years**\r\n\r\n*   This SSDI is effective for diagnosis years 2024+\r\n*   For cases diagnosed 2018-2023, this SSDI must be blank\r\n\r\n**Note 2: Bilateral retinoblastomas**\r\n\r\n*   This data item records the stage of the second eye when there are bilateral retinoblastomas.\r\n    *   **Code 7** if only one eye is involved (unilateral retinoblastoma)\r\n    *   Extension of one eye (unilateral retinoblastoma) is coded in Pediatric Primary Tumor\r\n*   If there are bilateral retinoblastomas, record the Stage Group of the lesser/lower stage in this data item (more advanced/higher stage is recorded in Pediatric Primary Tumor)\r\n    *   Do not record a stage (Stage 0-IV) in this data item if only one eye is invovled",
    "allowable_values": "0, 1, 2, 3, 4, 7, 8, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Stage 0\r\n\r\n*   Tumor confined to the globe\r\n*   Enucleation has not been performed\r\n*   Patient treated conservatively with either focal therapies or chemotherapy"
      },
      {
        "code": "1",
        "description": "Stage I\r\n\r\n*   Enucleation with negative margins (R0)\r\n*   Completely resected histologically"
      },
      {
        "code": "2",
        "description": "Stage II\r\n\r\n*   Enucleation with positive/microscopic residual tumor"
      },
      {
        "code": "3",
        "description": "Stage III\r\n\r\n*   Regional extension, involvement of \r\n    *   Orbit\r\n    *   Preauricular extension\r\n    *   Cervical lymph node involvement"
      },
      {
        "code": "4",
        "description": "Stage IV\r\n\r\n*   Distant metastatic disease"
      },
      {
        "code": "7",
        "description": "Not applicable: Only one eye is involved, and staging collected in Pediatric Primary Tumor, Pediatric Regional Nodes and Pediatric Mets\r\n\r\n*   Unilateral retinoblastoma"
      },
      {
        "code": "8",
        "description": "Not applicable: Information not collected for this case  \r\n(If this information is required by your standard setter, use of code 8 may result in an edit error.)"
      },
      {
        "code": "9",
        "description": "Not documented in medical record  \r\nInternational Retinoblastoma Staging System (IRSS) not assessed or unknown if assessed"
      }
    ]
  },
  {
    "item_number": "3862",
    "item_name": "JAK2",
    "item_data_type": "digits",
    "item_length": "1",
    "xml_naaccr_id": "jak2",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2017-11-14T17:32:52Z",
    "date_modified": "2022-05-27T07:24:11Z",
    "description": "Janus Kinase 2 (JAK2, JAK 2) is a gene mutation that increases susceptibility to several myeloproliferative neoplasms (MPNs). Testing for the JAK2 mutation is done on whole blood. Nearly all people with polycythemia vera, and about half of those with primary myelofibrosis and essential thrombocythemia, have the mutation. JAK2 analysis continues to increase in use for hematopoietic neoplasms.",
    "rationale": "JAK2 can be collected by the surveillance community for myeloproliferative neoplasms. Prior to 2018, HemeRetic SSF#1 was used for JAK2.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "No recommendation",
    "code_note": "Each Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "0-5, 7-9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "JAK2 result stated as negative"
      },
      {
        "code": "1",
        "description": "JAK2 positive for mutation V617F WITH or WITHOUT other mutations"
      },
      {
        "code": "2",
        "description": "JAK2 positive for exon 12 mutation"
      },
      {
        "code": "3",
        "description": "JAK2 positive for other specified mutation"
      },
      {
        "code": "4",
        "description": "JAK2 positive for more than one mutation other than V617F"
      },
      {
        "code": "5",
        "description": "JAK2 positive NOS  \n Specific mutation(s) not stated"
      },
      {
        "code": "7",
        "description": "Test ordered, results not in chart"
      },
      {
        "code": "8",
        "description": "Not applicable: Information not collected for this case  \n (If this item is required by your standard setter, use of code 8 will result in an edit error.)"
      },
      {
        "code": "9",
        "description": "Not documented in medical record  \n JAK2 not assessed or unknown if assessed"
      }
    ]
  },
