  {
    "item_number": "3866",
    "item_name": "KRAS",
    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "2018",
    "version_implemented": "18",
    "xml_naaccr_id": "kras",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2017-11-14T17:36:28Z",
    "date_modified": "2022-05-27T07:24:09Z",
    "description": "KRAS is an important signaling intermediate in the growth receptor pathway which controls cell proliferation and survival. KRAS is a protein with production controlled by the K-ras gene. When the K-ras gene is activated through mutation during colorectal carcinogenesis, production of KRAS continuously stimulates cell proliferation and prevents cell deaths. Activating mutations in KRAS are an adverse prognostic factor for colorectal carcinoma and predict a poor response to monoclonal anti-EGFR antibody therapy in advanced colorectal carcinoma.",
    "rationale": "KRAS is a Registry Data Collection Variable in AJCC. It was previously collected as Colon and Rectum CS SSF# 9.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "No recommendation",
    "code_note": "Each Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "0-4, 7-9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Normal  \n KRAS negative, KRAS wild type  \n Negative for (somatic) mutations, no alterations, no (somatic) mutations identified, not present, not detected"
      },
      {
        "code": "1",
        "description": "Abnormal (mutated) in codon(s) 12, 13 and/or 61"
      },
      {
        "code": "2",
        "description": "Abnormal (mutated) in codon 146 only"
      },
      {
        "code": "3",
        "description": "Abnormal (mutated), but not in codon(s) 12, 13, 61, or 146"
      },
      {
        "code": "4",
        "description": "Abnormal (mutated), NOS, codon(s) not specified"
      },
      {
        "code": "7",
        "description": "Test ordered, results not in chart"
      },
      {
        "code": "8",
        "description": "Not applicable: Information not collected for this case  \n (If this information is required by your standard setter, use of code 8 may result in an edit error.)"
      },
      {
        "code": "9",
        "description": "Not documented in medical record  \n KRAS not assessed or unknown if assessed"
      }
    ]
  },
