    "allowed_codes": [
      {
        "code": "0",
        "description": "Within normal limits"
      },
      {
        "code": "1",
        "description": "Less than 1.5 x N  \n (Less than 1.5 times the upper limit of normal for LDH)"
      },
      {
        "code": "2",
        "description": "1.5 to 10 x N  \n (Between 1.5 and 10 times the upper limit of normal for LDH)"
      },
      {
        "code": "3",
        "description": "Greater than 10 x N  \n (Greater than 10 times the upper limit of normal for LDH)"
      },
      {
        "code": "4",
        "description": "Post-Orchiectomy lactate dehydrogenase (LDH) range stated to be elevated"
      },
