  {
    "item_number": "2354",
    "item_name": "Longitude",
    "item_data_type": "text",
    "item_length": "11",
    "year_implemented": "2003",
    "version_implemented": "10",
    "xml_naaccr_id": "longitude",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "M"
    ],
    "section": "Patient-Confidential",
    "source_of_standard": "NAACCR",
    "date_created": "2011-11-10T00:47:21Z",
    "date_modified": "2023-06-29T06:58:01.849984Z",
    "description": "Paired with Latitude \\[2352\\], this represents the point location of the individual’s residence on the earth’s surface. It is typically determined by matching an address to a reference file or by identifying the residence using satellite imagery. This item is coded at the central registry, not by the reporting facility.",
    "rationale": "Latitude and Longitude comprise the universal standard for designating location on the earth’s surface. Geographic Information Systems software can be used to convert these values into projected coordinates for map display. \r\n\r\n**Allowable values and format**\r\n\r\nLongitude is an 11 digit numeric field, right justified, with up to six decimal places and an explicit decimal point. The format is x123.456789, where “x” is reserved for a negative sign for locations west of the Prime Meridian (0 degrees) and east of 180 degrees. The datum of the decimal degree data shall be North American Datum of 1983 (NAD 83).\r\n\r\nValues are in decimal degrees, not degrees/minutes/seconds.\r\n\r\nLongitude: -123.128943\r\n\r\nLongitude: -71 deg 7'' 44\"",
    "npcr_collect": "Required, when available",
    "coc_collect": "No recommendation",
    "seer_collect": "Supplementary/recommended",
    "cccr_collect": "No recommendation",
    "allowable_values": "Numbers, decimal point, negative sign"
  },
  {
    "item_number": "1182",
    "item_name": "Lymphovascular Invasion",
    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "2010",
    "version_implemented": "12",
    "xml_naaccr_id": "lymphVascularInvasion",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "AJCC",
    "date_created": "2011-11-09T09:47:21Z",
    "date_modified": "2022-05-27T07:24:07Z",
    "description": "Lymphovascular invasion (LVI) indicates the presence or absence of tumor cells in lymphatic channels (not lymph nodes) or blood vessels within the primary tumor as noted microscopically by the pathologist. LVI includes lymphatic invasion, vascular invasion, and lymphovascular invasion.",
    "rationale": "Presence or absence of cancer cells in the lymphatic ducts or blood vessels is useful for prognosis. CAP Protocols for some disease sites will be expanded to distinguish between lymphatic and small vessel invasion only, venous (large vessel) invasion only, and BOTH lymphatic and small vessel AND venous (large vessel) invasion.",
    "npcr_collect": "Required, when available",
    "coc_collect": "Required",
    "seer_collect": "Required, site specific",
    "cccr_collect": "Required, when available",
    "alternate_names": [
      "Lymph-vascular Invasion"
    ],
    "allowable_values": "0-4,8,9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Lymphovascular Invasion stated as Not Present"
      },
      {
        "code": "1",
        "description": "Lymphovascular Invasion Present/Identified (NOT used for thyroid and adrenal)"
      },
      {
        "code": "2",
        "description": "Lymphatic and small vessel invasion only (L)  \n OR  \n Lymphatic invasion only (thyroid and adrenal only)"
      },
      {
        "code": "3",
        "description": "Venous (large vessel) invasion only (V)  \n OR  \n Angioinvasion (thyroid and adrenal gland only)"
      },
      {
        "code": "4",
        "description": "BOTH lymphatic and small vessel AND venous (large vessel) invasion  \n OR  \n BOTH lymphatic AND angioinvasion (thyroid and adrenal only)"
      },
      {
        "code": "8",
        "description": "Not Applicable"
      },
      {
        "code": "9",
        "description": "Unknown/Indeterminate/not mentioned in path report"
      }
    ]
  },
  {
    "item_number": "3885",
    "item_name": "Lymphocytosis",
    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "2018",
    "version_implemented": "18",
    "xml_naaccr_id": "lymphocytosis",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2017-11-14T17:51:13Z",
    "date_modified": "2022-05-27T07:24:08Z",
    "description": "Lymphocytosis is defined by an excess of lymphocytes in the blood. In staging of Chronic Lymphocytic Leukemia/Small Lymphocytic Lymphoma (CLL/SLL), lymphocytosis is defined as an absolute lymphocyte count (ALC) greater than 5,000 cells/µL.",
    "rationale": "Lymphocytosis is a prognostic factor required for staging of Chronic Lymphocytic Leukemia/Small Lymphocytic Leukemia (CLL/SLL) in AJCC 8th edition, Chapter 79, *Hodgkin and Non-Hodgkin Lymphomas*.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "Required, site specific; when available",
    "code_note": "Each Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "0, 1, 5, 6, 7, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Lymphocytosis not present  \n Absolute lymphocyte count = 5,000 cells/µL"
      },
      {
        "code": "1",
        "description": "Lymphocytosis present  \n Absolute lymphocyte count > 5,000 cells/µL"
      },
      {
        "code": "5",
        "description": "Not applicable: Primary site is not C421"
      },
      {
        "code": "6",
        "description": "Lab value unknown, physician states lymphocytosis is present  \n Physician states Rai stage 0-IV"
      },
      {
        "code": "7",
        "description": "Test ordered, results not in chart"
      },
      {
        "code": "9",
        "description": "Not documented in medical record  \n Lymphocytosis not assessed or unknown if assessed  \n No Rai stage is documented in the record and there is no documentation of lymphocytosis"
      }
    ]
  },
