    "date_created": "2021-06-07T09:19:13Z",
    "date_modified": "2022-05-27T07:24:10Z",
    "description": "This data item records the results of a macroscopic evaluation of the mesorectum from a total mesorectal excision (TME)",
    "rationale": "Numerous studies have demonstrated the total mesorectal excision (TME) improves local recurrence rates and the corresponding survival by as much as 20%. Macroscopic pathologic assessment of the completeness of the mesorectum, scored as complete, partially complete, or incomplete, accurately predicts both local recurrence and distant metastasis.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required",
    "seer_collect": "Collected by SEER from CoC-accredited hospitals",
    "cccr_collect": "No recommendation",
    "allowable_values": "00, 10, 20, 30, 40, 99, Blank ",
    "allowed_codes": [
      {
        "code": "00",
        "description": "Patient did not receive TME"
      },
      {
        "code": "10",
        "description": "Incomplete"
      },
      {
        "code": "20",
        "description": "Nearly complete"
      },
      {
        "code": "30",
        "description": "Complete"
      },
      {
        "code": "40",
        "description": "TME performed not specified on pathology report as incomplete, nearly complete, or complete  \n TME performed, but pathology report not available Physician statement that TME performed, no mention of incomplete, nearly complete, or complete status"
      },
      {
        "code": "99",
        "description": "Unknown if TME performed"
      },
      {
        "code": "Blank",
        "description": "Site not rectum (C20.9)"
      }
    ]
  },
