  {
    "item_number": "2315",
    "item_name": "Medicare Beneficiary Identifier",
    "item_data_type": "text",
    "item_length": "11",
    "year_implemented": "2018",
    "version_implemented": "18",
    "xml_naaccr_id": "medicareBeneficiaryIdentifier",
    "xml_parent_id": "Patient",
    "record_types": [
      "A",
      "C",
      "M"
    ],
    "section": "Patient-Confidential",
    "source_of_standard": "NAACCR",
    "date_created": "2017-11-14T16:17:13Z",
    "date_modified": "2022-05-27T07:24:12Z",
    "description": "Congress passed the Medicare Access and CHIP Reauthorization ACT to remove Social Security Number (SSN) from Medicare ID card and replace the existing Medicare Health Insurance Claim Numbers with a Medicare Beneficiary Identifier (MBI). The MBI will be a randomly generated identifier that will not include a SSN or any personal identifiable information.",
    "rationale": "The MBI is a step to minimize the risk of identity theft for Medicare beneficiaries and reduce opportunities for fraud. In early 2018, CMB plans to issue new Medicare cards with an MBI. A Health Insurance Claim Number will still be assigned to each Medicare beneficiary and will still be used for internal data exchanges between CMS and the states, but the new MBI must be used in all interactions with the beneficiary, the provider community and all external partners. The collection of the MBI should not change how registries currently collect SSN.",
    "npcr_collect": "Required, when available",
    "coc_collect": "No recommendation",
    "seer_collect": "No recommendation",
    "cccr_collect": "No recommendation",
    "code_note": "*Note*: The Medicare Beneficiary Identifier (MBI) is randomly generated and has 11 characters, consisting of numbers and letters, entered without dashes. The MBI format: <https://www.cms.gov/Medicare/New-Medicare-Card/Understanding-the-MBI-with-Format.pdf>",
    "code_description": "In addition to MBI",
    "allowable_values": "Alphanumeric, Blank",
    "allowed_codes": [
      {
        "code": "Blank",
        "description": "Not Available, Non-Medicare Patient, Not Applicable, or Unknown"
      }
    ]
  },
  {
    "item_number": "3889",
    "item_name": "Methylation of O6-Methylguanine-Methyltransferase",
    "item_data_type": "digits",
    "item_length": "1",
    "xml_naaccr_id": "methylationOfO6MGMT",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2017-11-14T17:54:14Z",
    "date_modified": "2022-05-27T07:24:09Z",
    "description": "O6-Methylguanine-Methyltransferase (MGMT) is an enzyme in cells that repairs DNA. Methylation of the MGMT gene reduces production of MGMT enzyme and the ability of tumor cells to repair damage caused by chemotherapy. Methylation of MGMT is a prognostic and predictive factor for high grade gliomas.",
    "rationale": "Methylation of O6-Methylguanine-Methyltransferase (MGMT) is a Registry Data Collection Variable in AJCC. It was previously collected as Brain, CS SSF #4.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "No recommendation",
    "code_note": "Each Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "0-3, 6-9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "MGMT methylation absent/not present, unmethylated MGMT"
      },
      {
        "code": "1",
        "description": "MGMT methylation present, low level  \n Hypomethylated  \n Partial methylated"
      },
      {
        "code": "2",
        "description": "MGMT methylation present, high level  \n Hypermethylated"
      },
      {
        "code": "3",
        "description": "MGMT Methylation present, level unspecified"
      },
      {
        "code": "6",
        "description": "Benign or borderline tumor"
      },
      {
        "code": "7",
        "description": "Test ordered, results not in chart"
      },
      {
        "code": "8",
        "description": "Not applicable: Information not collected for this case  \n (If this item is required by your standard setter, use of code 8 will result in an edit error.)"
      },
      {
        "code": "9",
        "description": "Not documented in patient record  \n Cannot be determined by the pathologist  \n MGMT not assessed or unknown if assessed"
      }
    ]
  },
