    "date_modified": "2022-05-27T07:24:06Z",
    "description": "This field identifies whether bone is an involved metastatic site. The six Mets at Dx-Metastatic Sites fields provide information on specific metastatic sites for data analysis.",
    "rationale": "Information on site of metastatic disease at diagnosis has prognostic implications to survival among patients with initial late stage disease. Capturing data on where the patient’s metastatic lesions (including the number of locations) will be an important variable to include when looking at survival. Survival among metastatic patients is becoming increasingly important for cancer survivors.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required",
    "seer_collect": "Required",
    "cccr_collect": "Required",
    "allowable_values": "0, 1, 8, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "None; no bone metastases"
      },
      {
        "code": "1",
        "description": "Yes; distant bone metastases"
      },
      {
        "code": "8",
        "description": "Not applicable"
      },
      {
        "code": "9",
        "description": "Unknown whether bone is an involved metastatic site. Not documented in patient record."
      }
    ]
  },
