    "section": "Stage/Prognostic Factors",
    "source_of_standard": "SEER",
    "date_created": "2015-08-22T08:27:20Z",
    "date_modified": "2022-05-27T07:24:06Z",
    "description": "The six Mets at Dx-Metastatic Sites fields provide information on metastases for data analysis. This field identifies any type of distant involvement not captured in the Mets at Dx-Bone [1112], Mets at Dx-Brain [1113], Mets at Dx-Liver [1115], Mets at Dx-Lung [1116], and Mets at Dx-Distant LN [1114] fields. It includes involvement of other specific sites and more generalized metastases such as carcinomatosis. Some examples include but are not limited to the adrenal gland, bone marrow, pleura, malignant pleural effusion, peritoneum, and skin.",
    "rationale": "Information on site of metastatic disease at diagnosis has prognostic implications to survival among patients with initial late stage disease. Capturing data on where the patient’s metastatic lesions (including the number of locations) will be an important variable to include when looking at survival. Survival among metastatic patients is becoming increasingly important for cancer survivors.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required",
    "seer_collect": "Required",
    "cccr_collect": "Required",
    "allowable_values": "0, 1, 2, 8, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "None; no other metastases"
      },
      {
        "code": "1",
        "description": "Yes; distant metastases in known site(s) other than bone, brain, liver, lung or distant lymph nodes (Note: includes bone marrow involvement for lymphomas)"
      },
      {
        "code": "2",
        "description": "Generalized metastases such as carcinomatosis"
      },
      {
        "code": "8",
        "description": "Not applicable"
      },
      {
        "code": "9",
        "description": "Unknown whether any other metastatic site or generalized metastases. Not documented in patient record."
      }
    ]
  },
  {
    "item_number": "3890",
    "item_name": "Microsatellite Instability (MSI)",
    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "2018",
    "version_implemented": "18",
    "xml_naaccr_id": "microsatelliteInstability",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2017-11-14T17:55:01Z",
    "date_modified": "2022-05-27T07:24:06Z",
    "description": "Microsatellite Instability (MSI) is a form of genetic instability manifested by changes in the length of repeated single- to six-nucleotide sequences (known as DNA microsatellite sequences). High MSI, found in about 15% of colorectal carcinomas, is an adverse prognostic factor for colorectal carcinomas and predicts poor response to 5-FU chemotherapy (although the addition of oxaliplatin in FOLFOX regimens negates the adverse effects [page 266 AJCC manual]). High MSI is a hallmark of hereditary nonpolyposis colorectal carcinoma, also known as Lynch syndrome.",
    "rationale": "Microsatellite Instability (MSI) is a Registry Data Collection Variable in AJCC. It was previously collected as Colon and Rectum, CS SSF# 7.",
    "npcr_collect": "Required, site specific; when available",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "Required, site specific; when available",
    "code_note": "Each Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "0-2, 8, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Microsatellite instability (MSI) stable; microsatellite stable (MSS); negative, NOS  \n AND/OR  \n Mismatch repair (MMR) intact, no loss of nuclear expression of MMR proteins  \n MMR proficient (pMMR or MMR-P)"
      },
      {
        "code": "1",
        "description": "MSI unstable low (MSI-L)"
      },
      {
        "code": "2",
        "description": "MSI unstable high (MSI-H)  \n AND/OR  \n MMR deficient (dMMR or MMR-D), loss of nuclear expression of one or more MMR proteins"
      },
      {
        "code": "8",
        "description": "Not applicable: Information not collected for this case  \n (If this information is required by your standard setter, use of code 8 may result in an edit error.)"
      },
      {
        "code": "9",
        "description": "Not documented in medical record  \n MSI-indeterminate  \n MSI-equivocal  \n Microsatellite instability not assessed or unknown if assessed"
      }
    ]
  },
