    "item_name": "Mult Tum Rpt as One Prim",
    "item_data_type": "digits",
    "item_length": "2",
    "year_implemented": "2006",
    "version_implemented": "11",
    "xml_naaccr_id": "multTumRptAsOnePrim",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Cancer Identification",
    "source_of_standard": "SEER",
    "date_created": "2011-11-09T09:47:21Z",
    "date_modified": "2022-05-27T07:24:07Z",
    "description": "This data item is used to identify the type of multiple tumors in cases with multiple tumors that are abstracted and reported as a single primary using the SEER, IARC, or Canadian Cancer Registry multiple primary rules. Multiple tumors may individually exhibit *in situ*, invasive, or a combination of *in situ* and invasive behaviors. Multiple intracranial and central nervous system tumors may individually exhibit benign, borderline, malignant, or a combination of these behaviors. Multiple tumors found in the same organ or in a single primary site may occur at the time of initial diagnosis or later.",
    "rationale": "Patients with multiple tumors that are currently reported as a single primary may have a worse prognosis or more extensive treatment than patients with a single tumor. This data item will make it possible to identify important information about these cases for data analysis, and to compare individually reported cancer cases with historical data if the rules are changed.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Historically collected and currently transmitted",
    "seer_collect": "Historically collected and currently transmitted",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "Multiple Tumors Reported as Single Primary",
      "Type of Multiple Tumors Reported As One Primary"
    ],
    "format": "Right justified, zero filled",
    "code_description": "Refer to <http://seer.cancer.gov/tools/mphrules/index.html> for additional instructions",
    "allowable_values": "00, 10-12, 20, 30-32, 40, 80, 88, 99",
    "allowed_codes": [
      {
        "code": "00",
        "description": "Single tumor"
      },
      {
        "code": "10",
        "description": "Multiple benign"
      },
      {
        "code": "11",
        "description": "Multiple borderline"
      },
      {
        "code": "12",
        "description": "Benign and borderline"
      },
      {
        "code": "20",
        "description": "Multiple *in situ*"
      },
      {
        "code": "30",
        "description": "*In situ* and invasive"
      },
      {
        "code": "31",
        "description": "Polyp and adenocarcinoma"
      },
      {
        "code": "32",
        "description": "FAP with carcinoma"
      },
      {
        "code": "40",
        "description": "Multiple invasive"
      },
      {
        "code": "80",
        "description": "Unknown *in situ* or invasive"
      },
      {
        "code": "88",
        "description": "NA"
      },
      {
        "code": "99",
        "description": "Unknown"
      }
    ]
  },
