      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR/SEER",
    "date_created": "2024-04-26T09:42:00.425732Z",
    "date_modified": "2024-05-30T20:55:02.014425Z",
    "description": "n-MYC Amplification is a gene that normally regulates cell growth. Studies have shown that n-MYC amplification is an indicator of poor prognosis and increased risk of unfavorable outcomes in patients with neuroblastoma.\r\n\r\nThis field indicates the n-MYC status of a neuroblastoma tumor after a pathologic specimen is obtained.",
    "general_notes": "**Source documents:** molecular pathology report (may be addendum to original pathology report)\r\n\r\nFor further information, refer to the **Neuroblastoma** cancer protocol published by the College of American Pathologists.",
    "rationale": "This is part of the National Childhood Cancer Registry (NCCR) project to collect more specific information on pediatric patients. Registries part of the NCCR will start collection on specific pediatric data items with 2024+ diagnoses.",
    "npcr_collect": "No recommendation",
    "coc_collect": "No recommendation",
    "seer_collect": "Required, site specific; when available",
    "cccr_collect": "No recommendation",
    "code_note": "**Note 1: Effective years**\r\n\r\n*   This SSDI is effective for diagnosis years 2024+\r\n*   For cases diagnosed 2018-2023, this SSDI must be blank\r\n\r\n**Note 2: Physician statement** \r\n\r\nPhysician statement of n-MYC can be used to code this data item when no other information is available.",
    "allowable_values": "0, 1, 2, 7, 8, 9,",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Not amplified/negative"
      },
      {
        "code": "1",
        "description": "Amplified/positive"
      },
      {
        "code": "2",
        "description": "Gain"
      },
      {
        "code": "7",
        "description": "Test ordered, results not in chart"
      },
      {
        "code": "8",
        "description": "Not applicable: Information not collected for this case\r\n\r\n(If this information is required by your standard setter, use of code 8 may result in an edit error)"
      },
      {
        "code": "9",
        "description": "Not documented in medical record\r\n\r\nCannot be determined by pathologist\r\n\r\nNot applicable (secondary to previous chemotherapy)  \r\nn-MYC not assessed or unknown if assessed"
      }
    ]
  },
