  {
    "item_number": "2232",
    "item_name": "Name--Birth Surname",
    "item_data_type": "text",
    "item_length": "40",
    "year_implemented": "2021",
    "version_implemented": "21",
    "xml_naaccr_id": "nameBirthSurname",
    "xml_parent_id": "Patient",
    "record_types": [
      "A",
      "C",
      "M"
    ],
    "section": "Patient-Confidential",
    "source_of_standard": "NAACCR",
    "date_created": "2020-04-29T03:16:32Z",
    "date_modified": "2022-05-27T07:24:06Z",
    "description": "Last name (surname) of patient at birth, regardless of gender or marital status.    \nOther alternate names should be recorded in the data item, Name--Alias [2280].",
    "rationale": "This can be used to link reports on a person whose surname might be different on different documents. It is also useful when using a Spanish surname algorithm to categorize ethnicity.",
    "npcr_collect": "Required",
    "coc_collect": "No recommendation",
    "seer_collect": "Required",
    "cccr_collect": "Required, when available",
    "format": "Mixed case; Left-justified, and blank-filled. ",
    "code_note": "The field should be left blank if the birth surname is not known or not applicable. Since a value in this field may be used by linkage software or other computer algorithms, only legitimate surnames are allowable, and any variation of “unknown” or “not applicable” is not allowable.  \n  \n*Note:* This data item was introduced to be a gender-neutral birth-surname data item, analogous to Name--Maiden [2390]. It is to have been populated in the 2021 conversion by values in [2390]. The original (Name--Maiden) data item had been supported by CoC until January 1, 2003.",
    "allowable_values": "Embedded spaces, hyphens, apostrophes. No other special characters are allowed."
  },
