    "item_number": "3896",
    "item_name": "NCCN International Prognostic Index (IPI)",
    "item_data_type": "text",
    "item_length": "2",
    "year_implemented": "2018",
    "version_implemented": "18",
    "xml_naaccr_id": "nccnInternationalPrognosticIndex",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2017-11-14T07:20:58Z",
    "date_modified": "2022-08-04T09:05:49Z",
    "description": "The NCCN International Prognostic Index (IPI) (previously only \"IPI\") is used to define risk groups for specific lymphomas using a 0-8 score range, based on age, stage, number of extranodal sites of involvement, patient''s performance status and pretreatment LDH level. ",
    "rationale": "NCCN International Prognostic Index (IPI) is a Registry Data Collection Variable in AJCC. It was previously collected for Lymphomas, SSF# 3.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "No recommendation",
    "code_note": "Each Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "00-08, X1, X2, X3, X4, X8, X9",
    "allowed_codes": [
      {
        "code": "00-08",
        "description": "0-8 points"
      },
      {
        "code": "X1",
        "description": "Stated as low risk (0-1 point)"
      },
      {
        "code": "X2",
        "description": "Stated as low intermediate risk (2-3 points)"
      },
      {
        "code": "X3",
        "description": "Stated as intermediate risk (4-5 points)"
      },
      {
        "code": "X4",
        "description": "Stated as high risk (6-8 points)"
      },
      {
        "code": "X8",
        "description": "Not applicable: Information not collected for this case  \n (If this item is required by your standard setter, use of code X8 will result in an edit error.)"
      },
      {
        "code": "X9",
        "description": "Not documented in medical record  \n NCCN International Prognostic Index (IPI) not assessed or unknown if assessed"
      }
    ]
  },
