    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "2021",
    "version_implemented": "21",
    "xml_naaccr_id": "ncdbCovid19TxImpact",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Special Use",
    "source_of_standard": "CoC",
    "date_created": "2020-06-10T06:46:42Z",
    "date_modified": "2022-05-27T07:24:13Z",
    "description": "Was the first course of treatment (diagnosis, staging, treatment or other cancer management events) impacted by hospital availability (limited access to facilities or postponement of non-essential procedures) due to COVID-19 pandemic? (No; First Course Delayed; First Course Altered; First Course Cancelled). Collection based on diagnosis years 2020 and 2021.",
    "rationale": "To evaluate the impact of COVID-19 pandemic on cancer patients.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Historically collected and currently transmitted",
    "seer_collect": "Historically collected and currently transmitted when available",
    "cccr_collect": "No recommendation",
    "format": "numeric",
    "code_note": "*Note*: This item may be left blank.",
    "allowable_values": "1-5, 9",
    "allowed_codes": [
      {
        "code": "1",
        "description": "Treatment not affected; active surveillance, no change"
      },
      {
        "code": "2",
        "description": "First Course of Treatment timeline delayed"
      },
      {
        "code": "3",
        "description": "First Course of Treatment plan altered"
      },
      {
        "code": "4",
        "description": "Cancelled First Course of Treatment"
      },
      {
        "code": "5",
        "description": "Patient refused treatment due to COVID-19"
      },
      {
        "code": "9",
        "description": "Not known if treatment affected"
      }
    ]
  },
