  {
    "item_number": "1633",
    "item_name": "Neoadjuvant Therapy-Clinical Response",
    "item_data_type": "text",
    "item_length": "1",
    "year_implemented": "2021",
    "version_implemented": "21",
    "xml_naaccr_id": "neoadjuvTherapyClinicalResponse",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Treatment-1st Course",
    "source_of_standard": "SEER",
    "date_created": "2020-04-29T06:59:43Z",
    "date_modified": "2024-05-01T21:26:23.636095Z",
    "description": "This data item records the clinical outcomes of neoadjuvant therapy prior to planned surgical resection.",
    "rationale": "This data items provides information related to the quality of care and describes the clinical outcomes after neoadjuvant therapy. This data item provides prognostically relevant information by quantifying the extent of therapy-induced tumor regression. Therefore, this item can provide a better risk stratification for patients who received neoadjuvant therapy. In addition, this data item can contribute to assessments of cancer care quality.\r\n\r\nThis data item records the clinical outcomes of neoadjuvant therapy as determined by the managing physician (oncologic surgeon, radiation oncologist or medical oncologist).\r\n\r\nFor the purposes of this data item, neoadjuvant therapy is defined as systemic treatment (chemotherapy, endocrine / hormone therapy, targeted therapy, immunotherapy, or biological therapy) and/or radiation therapy given to shrink a tumor before surgical resection.",
    "npcr_collect": "No recommendation",
    "coc_collect": "No recommendation",
    "seer_collect": "Required",
    "cccr_collect": "No recommendation",
    "allowable_values": "0-9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Neoadjuvant therapy not given"
      },
      {
        "code": "1",
        "description": "Complete clinical response (CR)(per managing/treating physician statement)"
      },
      {
        "code": "2",
        "description": "Partial clinical response (PR) (per managing/treating physician statement)"
      },
      {
        "code": "3",
        "description": "Progressive disease (PD)(per managing/treating physician statement)"
      },
      {
        "code": "4",
        "description": "Stable disease (SD)(per managing/treating physician statement)"
      },
      {
        "code": "5",
        "description": "No response (NR) (per managing/treating physician statement  \n Not stated as progressive disease (PD) or stable disease (SD)"
      },
      {
        "code": "6",
        "description": "Neoadjuvant therapy done, managing/treating physician interpretation not available, treatment response inferred from imaging, biomarkers, or yc stage"
      },
      {
        "code": "7",
        "description": "Complete clinical response based on biopsy results from pathology report (per pathologist assessment)"
      },
      {
        "code": "8",
        "description": "Neoadjuvant therapy done, response not documented or unknown"
      },
      {
        "code": "9",
        "description": "Unknown if neoadjuvant therapy performed  \n Death Certificate only (DCO)"
      }
    ]
  },
  {
    "item_number": "1634",
    "item_name": "Neoadjuvant Therapy-Treatment Effect",
    "item_data_type": "text",
    "item_length": "1",
    "year_implemented": "2021",
    "version_implemented": "21",
    "xml_naaccr_id": "neoadjuvTherapyTreatmentEffect",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Treatment-1st Course",
    "source_of_standard": "SEER",
    "date_created": "2020-04-29T03:01:00Z",
    "date_modified": "2022-05-27T07:24:06Z",
    "description": "This data item records the pathologist’s statement of neoadjuvant treatment effect on the primary tumor from the surgical pathology report. Whenever treatment effect definitions are recommended by or available in CAP Cancer Protocols, this data item follows the CAP definitions indicating absent or present effect. When specific CAP definitions are not available, registrars should use treatment effect general use categories.",
    "rationale": "This data item provides information related to the quality of care and describes the pathological outcomes after neoadjuvant therapy. This data item provides prognostically relevant information by quantifying the extent of therapy-induced tumor regression. Therefore, this item can provide a better risk stratification for patients who received neoadjuvant therapy. In addition, this data item can contribute to assessments of cancer care quality.",
    "npcr_collect": "No recommendation",
    "coc_collect": "No recommendation",
    "seer_collect": "Required",
    "cccr_collect": "No recommendation",
    "allowable_values": "0-4, 6, 7, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Neoadjuvant therapy not given/no known presurgical therapy"
      },
      {
        "code": "1-4",
        "description": "Site-specific code; type of response"
      },
      {
        "code": "6",
        "description": "Neoadjuvant therapy completed and surgical resection performed, response not documented or unknown  \n Cannot be determined"
      },
      {
        "code": "7",
        "description": "Neoadjuvant therapy completed and planned surgical resection not performed"
      },
      {
        "code": "9",
        "description": "Unknown if neoadjuvant therapy performed  \n Unknown if planned surgical procedure performed after completion of neoadjuvant therapy  \n Death Certificate only (DCO)"
      }
    ]
  },
  {
