    "description": "This data item records whether the patient had neoadjuvant therapy prior to planned definitive surgical resection of the primary site.",
    "rationale": "This data items provides information related to the quality of care and describes whether a patient had neoadjuvant therapy.   \n  \nFor the purposes of this data item, neoadjuvant therapy is defined as systemic treatment (chemotherapy, endocrine / hormone therapy, targeted therapy, immunotherapy, or biological therapy) and/or radiation therapy before intended or performed surgical resection to improve local therapy and long term outcomes.",
    "npcr_collect": "No recommendation",
    "coc_collect": "No recommendation",
    "seer_collect": "Required",
    "cccr_collect": "No recommendation",
    "allowable_values": "0-3, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "No neoadjuvant therapy, no treatment before surgery, surgical resection not part of first course of treatment plan  \n Autopsy only"
      },
      {
        "code": "1",
        "description": "Neoadjuvant therapy completed according to treatment plan and guidelines"
      },
      {
        "code": "2",
        "description": "Neoadjuvant therapy started, but not completed OR unknown if completed"
      },
      {
        "code": "3",
        "description": "Limited systemic exposure when the intent was not neoadjuvant; treatment did not meet the definition of neoadjuvant therapy"
      },
      {
        "code": "9",
        "description": "Unknown if neoadjuvant therapy performed  \n Death Certificate only (DCO)"
      }
    ]
  },
