    "item_name": "NRAS Mutational Analysis",
    "item_data_type": "text",
    "item_length": "1",
    "year_implemented": "2021",
    "version_implemented": "21",
    "xml_naaccr_id": "nrasMutationalAnalysis",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2020-04-29T02:52:00Z",
    "date_modified": "2022-05-27T07:24:13Z",
    "description": "NRAS is a signaling intermediate in the growth receptor pathway. Certain NRAS mutations predict poor response to anti-EGFR therapy in patients with metastatic colorectal cancer.",
    "rationale": "NRAS mutational analysis is recommended in clinical guidelines for patients with metastatic colon cancer who are being considered for anti-EGFR therapy. It is a new data item for cases diagnosed 01/01/2021+.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required",
    "cccr_collect": "No recommendation",
    "code_note": "Each Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "0-2, 4, 7-9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Normal  \n NRAS negative; NRAS wild type  \n Negative for (somatic) mutations, no alterations, no (somatic) mutations identified, not present, not detected"
      },
      {
        "code": "1",
        "description": "Abnormal (mutated)/detected in codon(s) 12, 13, and/or 61"
      },
      {
        "code": "2",
        "description": "Abnormal (mutated)/detected, codon(s) specified but not in codon(s) 12, 13, or 61"
      },
      {
        "code": "4",
        "description": "Abnormal (mutated), NOS, codon(s) not specified"
      },
      {
        "code": "7",
        "description": "Test ordered, results not in chart"
      },
      {
        "code": "8",
        "description": "Not applicable: Information not collected for this case  \n If this information is required by your standard setter, use of code 8 may result in an edit error."
      },
      {
        "code": "9",
        "description": "Not documented in medical record  \n NRAS not assessed or unknown if assessed"
      }
    ]
  },
