    "date_created": "2017-11-14T12:27:35Z",
    "date_modified": "2022-05-27T07:24:08Z",
    "description": "Identifies the total number of phases administered to the patient during the first course of treatment. A “phase” consists of one or more consecutive treatments delivered to the same anatomic volume with no change in the treatment technique. Although the majority of courses of radiation therapy are completed in one or two phases (historically, the “regional” and “boost” treatments) there are occasions in which three or more phases are used, most typically with head and neck malignancies. This data item is required for CoC-accredited facilities as of cases diagnosed 01/01/2018 and later.",
    "rationale": "The number of phases of radiation treatment is used to evaluate patterns of radiation therapy and the treatment schedule.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required",
    "seer_collect": "Required, when available",
    "cccr_collect": "No recommendation",
    "format": "right justified, zero-filled",
    "allowable_values": "00, 01, 02, 03, 04, 99 ",
    "allowed_codes": [
      {
        "code": "00",
        "description": "No radiation treatment"
      },
      {
        "code": "01",
        "description": "1 phase"
      },
      {
        "code": "02",
        "description": "2 phases"
      },
      {
        "code": "03",
        "description": "3 phases"
      },
      {
        "code": "04",
        "description": "4 or more phases"
      },
      {
        "code": "99",
        "description": "Unknown number of phases; Unknown if radiation therapy administered"
      }
    ]
  },
