  {
    "item_number": "3769",
    "item_name": "Over-ride CS 20",
    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "2011",
    "version_implemented": "12.1",
    "xml_naaccr_id": "overRideCs20",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Edit Overrides/Conversion History/System Admin",
    "source_of_standard": "AJCC/NPCR",
    "date_created": "2011-11-09T09:47:21Z",
    "date_modified": "2022-05-27T07:24:05Z",
    "description": "Some computer edits identify errors. Others indicate possible errors that require manual review for resolution. To eliminate the need to review the same cases repeatedly, over-ride flags have been developed to indicate that data in a record (or records) have been reviewed and, while unusual, are correct.  \n  \nOver-ride CS 20 has been designated as a flag for directly coded SEER Summary Stage 2000 [759] to support CDC''s National Program of Cancer Registries (NPCR) requirements.",
    "rationale": "Some edits check for code combinations that are possible, but quite rare. If the code combination generates an error message and review of the case indicates that the codes are correct for the case, then the over-ride flag is used to skip the edit in the future. For diagnosis years 2012 and later, NPCR permits the use of SEER Summary Stage 2000 [759] in those cases where collection of Collaborative Stage version 2 data items is not feasible due to a lack of data or staffing and time constraints at the local or central cancer registry. Over-ride CS 20 has been designated as a special-purpose flag to identify cases where SEER Summary Stage 2000 [759] is directly coded and reported in lieu of Derived SS2000 [3020], in accordance with NPCR reporting requirements.  \n  \nThe Over-ride CS 20 value of \"1\", set by the user, identifies a record with NAACCR data item 759 used to report Summary Stage 2000 as permitted by NPCR requirements only; Over-ride CS 20 is left blank for all other cases.",
    "npcr_collect": "Historically collected and currently transmitted",
    "coc_collect": "Historically collected and currently transmitted",
    "seer_collect": "Historically collected and currently transmitted",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "Direct Summary Stage 2000 Flag"
    ],
    "allowable_values": "1, blank",
    "allowed_codes": [
      {
        "code": "1",
        "description": "Directly coded SEER Summary Stage 2000 [759] used to report Summary Stage; Derived Summary Stage 2000 [3020] must be blank."
      },
      {
        "code": "Blank",
        "description": "Derived Summary Stage 2000 [3020] reported using Collaborative Stage Data Collection System or case diagnosed prior to 2012."
      }
    ]
  },
  {
