  {
    "item_number": "1989",
    "item_name": "Over-ride Site/TNM-StgGrp",
    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "2001",
    "version_implemented": "9",
    "xml_naaccr_id": "overRideSiteTnmStggrp",
