  {
    "item_number": "20",
    "item_name": "Patient ID Number",
    "item_data_type": "digits",
    "item_length": "8",
    "xml_naaccr_id": "patientIdNumber",
    "xml_parent_id": "Patient",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Record ID",
    "source_of_standard": "Reporting Registry",
    "date_created": "2011-11-09T09:47:21Z",
    "date_modified": "2022-05-27T07:24:10Z",
    "description": "Unique number assigned to an individual patient by the central registry. The central registry will assign this same number to all of the patient’s subsequent tumors (records).   \n  \nPatient ID Number will only differ when multiple central registries accession the same patient. Each central registry will assign their unique Patient ID Number.  \n  \nNAACCR recommends that the registry should not reissue or reuse this number when a patient’s record is deleted from the files.  \n  \nIn the transmit file (data exchange) this number will be the Patient ID Number assigned by the sending registry as defined in Registry ID [40].",
    "rationale": "Provides the central registry with a unique identification number that will link all records (multiple tumors) for the same patient. The unique number also allows the central registry to identify the patient when there are multiple reports from different hospitals.",
    "npcr_collect": "Required",
    "coc_collect": "No recommendation",
    "seer_collect": "Required",
    "cccr_collect": "Required, when available",
    "format": "Right justified, zero filled"
  },
  {
    "item_number": "21",
    "item_name": "Patient System ID-Hosp",
    "item_data_type": "digits",
    "item_length": "8",
    "year_implemented": "2006",
    "version_implemented": "11",
    "xml_naaccr_id": "patientSystemIdHosp",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Record ID",
    "source_of_standard": "NAACCR",
    "date_created": "2011-11-09T09:47:21Z",
    "date_modified": "2022-05-27T07:24:12Z",
    "description": "The unique, non-repeating number automatically assigned to patients by the hospital tumor registry software system. The same number is used for all the patient''s subsequent tumors. This Patient System ID-Hosp number should not be reused when a patient is deleted.  \n  \nThis number is different from Accession Number-Hosp [550]. While Accession Number-Hosp [550] is subject to change, the Patient System ID-Hosp number is created and maintained by the hospital tumor registry’s software system, and requires no key entry. Because the Patient System ID-Hosp number is unchanging, it affords an absolute linkage between a hospital patient record and a central registry’s patient record.",
    "rationale": "This provides a stable identifier to link back to all reported tumors for a patient. It also serves as a reliable linking identifier; useful when central registries send follow-up information back to hospitals. Other identifiers such as social security number and medical record number, while useful, are subject to change and are thus less useful for this type of record linkage.",
    "npcr_collect": "No recommendation",
    "coc_collect": "No recommendation",
    "seer_collect": "No recommendation",
    "cccr_collect": "No recommendation",
    "format": "Right justified, zero filled"
  },
  {
    "item_number": "1174",
    "item_name": "PD-L1",
    "item_data_type": "text",
    "item_length": "5",
    "year_implemented": "2025",
    "version_implemented": "25",
    "xml_naaccr_id": "pdl1",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2024-04-21T08:22:23.640913Z",
    "date_modified": "2025-01-18T03:10:37.88967Z",
    "description": "The absence or presence of PD-L1 expression determines if the tumor will respond to treatment with a targeted inhibitor (immunotherapy). PD-L1 is done for Non-small cell lung cancers (NSCLC).",
    "rationale": "PD-L1 is recommended by treatment guidelines for lung cancer to determine if the patient may benefit from checkpoint inhibitor drugs (immunotherapy). It is a new data item for cases diagnosed 1/1/2025+.",
    "npcr_collect": "Required, site specific; when available",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "Required, site specific; when available",
    "code_note": "**Note 1:** This SSDI is effective for diagnosis years 2025+. \r\n\r\n*   For cases diagnosed 2018-2024, leave this SSDI blank\r\n\r\n**Note 2:** Physician statement PD-L1 can be used to code this data item when no other information is available.\r\n\r\n**Note 3:** The absence or presence of PD-L1 expression determines if the tumor will respond to treatment with a targeted inhibitor. PDL-1 is done for Non-Small Cell lung cancers (NSCLC)\r\n\r\n**Note 4:** If neoadjuvant therapy is given, record the assay from tumor specimens prior to neoadjuvant therapy. \r\n\r\n*   If neoadjuvant therapy is given and there are no PD-L1 results from pre-treatment specimens, report the findings from post-treatment specimens",
    "allowable_values": "0.0, 0.1-100.0, XXX.2, XXX.3, XXX.4, XXX.7, XXX.8, XXX.9",
    "allowed_codes": [
      {
        "code": "0.0",
        "description": "No PD-L1 expression identified\r\n\r\nTumor Proportion Score (TPS) = 0%"
      },
      {
        "code": "0.1-100.0",
