    "date_modified": "2024-05-30T20:46:07.337209Z",
    "description": "Pediatric Mets is part of the Pediatric Staging data collection system and is used **to classify the distant site(s) of metastatic involvement at time of diagnosis.** See also Pediatric Primary Tumor **\\[1136\\]** and Pediatric Regional Nodes **\\[1137\\]**. **Effective for cases diagnosed 1/1/2024 and forward.**",
    "rationale": "Pediatric Mets is used to calculate Derived Pediatric M **\\[1144\\]** (when applicable)**.** Derivation will occur at the level of the central registry.",
    "npcr_collect": "No recommendation",
    "coc_collect": "No recommendation",
    "seer_collect": "Required, site specific; when available",
    "cccr_collect": "No recommendation",
    "code_note": "Schema-specific codes where needed",
    "code_description": "See the most current version of [SEER\\RSA](https://staging.seer.cancer.gov/) (Pediatric Staging tab) for rules and site-specific codes and coding structures",
    "allowable_values": "00, schema-specific codes where needed, 70, 88, 99",
    "allowed_codes": [
      {
        "code": "00",
        "description": "No distant metastasis"
      },
      {
        "code": "70",
        "description": "Distant metastasis, NOS"
      },
      {
        "code": "88",
        "description": "Not applicable"
      },
      {
        "code": "99",
        "description": "Unknown; distant metastasis not stated  \r\nNot documented in medical record\r\n\r\n  \r\nDeath Certificate Only"
      }
    ]
  },
