    "seer_collect": "Required, site specific; when available",
    "cccr_collect": "No recommendation",
    "code_note": "Schema-specific codes where needed.",
    "code_description": "See the most current version of [SEER\\RSA](https://staging.seer.cancer.gov/) (Pediatric tab) for rules and site-specific codes and coding structures",
    "allowable_values": "000, Schema-Specific Does where needed, 800, 888, 999",
    "allowed_codes": [
      {
        "code": "000",
        "description": "In situ, intraepithelial, noninvasive, non-infiltrating"
      },
      {
        "code": "800",
        "description": "No evidence of primary tumor"
      },
      {
        "code": "888",
        "description": "Not applicable"
      },
      {
        "code": "999",
        "description": "Unknown; extension not stated  \r\nPrimary tumor cannot be assessed  \r\nNot documented in patient record\r\n\r\nDeath Certificate Only"
      }
    ]
  },
