    "description": "Peripheral blood involvement, summarized in \"B category\", refers to the percentage of peripheral blood lymphocytes that are atypical (Sezary) cells and whether they are \"Clone negative\" or \"Clone positive\".",
    "rationale": "Peripheral blood involvement is a prognostic factor required in AJCC 8th edition, Chapter 81 *Primary Cutaneous Lymphomas*, for staging of Mycosis Fungoides and Sezary Syndrome. It was previously collected as Mycosis Fungoides, CS SSF #1.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "Required, site specific; when available",
    "code_note": "Each Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "0-7, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Absence of significant blood involvement  \n 5% or less of peripheral blood lymphocytes are atypical (Sezary) cells  \n Clone unknown  \n Stated as B0"
      },
      {
        "code": "1",
        "description": "Absence of significant blood involvement  \n 5% or less of peripheral blood lymphocytes are atypical (Sezary) cells  \n Clone negative  \n Stated as B0a"
      },
      {
        "code": "2",
        "description": "Absence of significant blood involvement:  \n 5% or less of peripheral blood lymphocytes are atypical (Sezary) cells  \n Clone positive  \n Stated as B0b"
      },
      {
        "code": "3",
        "description": "Low blood tumor burden  \n More than 5% of peripheral blood lymphocytes are atypical (Sezary) cells but does not meet the criteria of B2  \n Clone unknown  \n Stated as B1"
      },
      {
        "code": "4",
        "description": "Low blood tumor burden  \n More than 5% of peripheral blood lymphocytes are atypical (Sezary) cells but does not meet the criteria of B2  \n Clone negative  \n Stated as B1a"
      },
      {
        "code": "5",
        "description": "Low blood tumor burden  \n More than 5% of peripheral blood lymphocytes are atypical (Sezary) cells but does not meet the criteria of B2  \n Clone positive  \n Stated as B1b"
      },
      {
        "code": "6",
        "description": "High blood tumor burden  \n Greater than or equal to 1000 Sezary cells per microliter (uL)  \n Clone positive  \n Stated as B2"
      },
      {
        "code": "7",
        "description": "Test ordered, results not in chart"
      },
      {
        "code": "9",
        "description": "Not documented in medical record  \n Peripheral Blood Involvement not assessed or unknown if assessed"
      }
    ]
