    "coc_collect": "Required",
    "seer_collect": "Required, when available",
    "cccr_collect": "No recommendation",
    "format": "Right Justified, zero filled",
    "allowable_values": "00000-99999",
    "allowed_codes": [
      {
        "code": "00000",
        "description": "Radiation therapy was not administered"
      },
      {
        "code": "00001-99997",
        "description": "Record the actual Phase I dose delivered in cGy"
      },
      {
        "code": "99998",
        "description": "Not applicable, brachytherapy or radioisotopes administered to the patient"
      },
      {
        "code": "99999",
        "description": "Regional radiation therapy was administered but dose is unknown, it is unknown whether radiation therapy was administered. Death Certificate only."
      }
    ]
  },
