    "item_number": "3915",
    "item_name": "Progesterone Receptor Summary",
    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "2018",
    "version_implemented": "18",
    "xml_naaccr_id": "progesteroneRecepSummary",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2017-11-15T02:44:01Z",
    "date_modified": "2023-05-12T06:41:00.783444Z",
    "description": "PR (Progesterone Receptor) Summary is a summary of results from the progesterone receptor (PR) assay.",
    "rationale": "This data item is required for prognostic stage grouping in AJCC 8th edition, Chapter 48, _Breast_. It was previously collected as Breast CS SSF # 2.",
    "npcr_collect": "Required, site specific",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "Required, site specific; when available",
    "code_note": "Note 1: Physician statement of PR (Progesterone Receptor) Summary status can be used to code this data item when no other information is available.\r\n\r\nNote 2: The result of the PR test performed on the primary breast tissue is to be recorded in this data item.\r\n\r\nNote 3: Results from nodal or metastatic tissue may be used ONLY when there is no evidence of primary tumor.\r\n\r\nNote 4: In cases where PR is reported on more than one breast tumor specimen, record the highest value. If any sample is positive, record as positive.\r\n\r\n•    Exception: If PR is positive on an in situ specimen and PR is negative on all tested invasive specimens, code PR as negative (code 0).\r\n\r\nNote 5: If neoadjuvant therapy is given, record the assay from tumor specimens prior to neoadjuvant therapy.\r\n\r\n  • If neoadjuvant therapy is given and there are no PR results from pre-treatment specimens, report the findings from post-treatment specimens.\r\n\r\nNote 6: If the patient is PR positive and node negative, a multigene test such as Oncotype Dx may be performed, in which case another PR test will be performed. Do not record the results of that test in this field.\r\n\r\n  • Record only the results of the test which made the patient eligible to be given the multigene test.  \r\n\r\nEach Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "0, 1, 7, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "PR negative (0.0% or less than 1%)"
      },
      {
        "code": "1",
        "description": "PR positive"
      },
      {
        "code": "7",
        "description": "Test ordered, results not in chart"
      },
      {
        "code": "9",
        "description": "Not documented in medical record  \n Cannot be determined (indeterminate)  \n PR (Progesterone Receptor) Summary status not assessed or unknown if assessed"
      }
    ]
  },
