  {
    "item_number": "1172",
    "item_name": "Post Transplant Lymphoproliferative Disorder-PTLD",
    "item_data_type": "numeric",
    "item_length": "1",
    "year_implemented": "2025",
    "version_implemented": "25",
    "xml_naaccr_id": "ptld",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2024-04-21T00:19:48.687614Z",
    "date_modified": "2024-05-29T04:19:19.749347Z",
    "description": "Post Transplant Lymphoproliferative Disorder (PTLD) is a lymphoid proliferation arising in a recipient of a solid organ transplant, allogeneic bone marrow transplantation, or an umbilical cord blood transfusion. The patient must  have a history of a solid organ transplant or an allogeneic bone marrow transplant. Both polymorphic and monomorphic PTLD are actually caused by post-transplant immunosuppression. Most cases of PTLD occur within a year of transplantation; however, they can occur any time after the transplant. Monomorphic PTLD may have histology indistinguishable from that of various malignant hematopoietic neoplasms, particularly lymphomas such as Diffuse Large B-cell Lymphoma.",
    "rationale": "The presence of PTLD, either polymorphic or monomorphic, has clinical significance and prognostic value, especially in the Pediatric and Adolescence and Young Adult (AYA) populations.",
    "npcr_collect": "Required, site specific; when available",
    "coc_collect": "Required",
    "seer_collect": "Required, site specific",
    "cccr_collect": "Required, site specific; when available",
    "code_note": "Note 1: Post Transplant Lymphoproliferative Disorder (PTLD) is a lymphoid proliferation arising in a recipient of a solid organ transplant, allogeneic bone marrow transplantation, or an umbilical cord blood transfusion. The development of PTLD is clinically significant and a prognostic indicator.\r\n\r\n*   Code 0 if the patient has NO or UNKNOWN history of a solid organ transplant, allogeneic bone marrow transplantation, or an umbilical cord blood transplant AND there is no mention of PTLD in the pathology report\r\n\r\nNote 2: There are several types of PTLD\r\n\r\n*   Polymorphic PTLD: This is a PTLD by itself, there is no histology that is identical to that of another other type of Hematopoietic neoplasm. This type of PTLD is NOT collected in this data item.\r\n*   Monomorphic PTLD (Code 2): This is the most common PTLD and may have a histology identical to that of another malignant hematopoietic neoplasm. Most common, but not limited to, diffuse large B-cell lymphoma (DLBCL) and Burkitt lymphoma \r\n*   Classic Hodgkin lymphoma-PTLD type (Code 3): Under the microscope, Reed-Sternberg cells, which are associated with Hodgkin lymphoma are present\r\n*   PTLD, NOS (Code 4): Used when only PTLD (NOS) is documented and there is no mention of monomorphic or Hodgkin like type\r\n\r\nNote 3: This SSDI is effective for diagnosis years 2025+. \r\n\r\n*   For cases diagnosed prior to 2025, leave this SSDI blank.",
    "allowable_values": "0, 1, 2, 4, 8",
    "allowed_codes": [
      {
        "code": "0",
        "description": "PTLD not documented on the pathology report or in the medical recordPatient has NO history, or history UNKNOWN, of solid organ transplant, allogeneic bone marrow transplantation, or an umbilical cord blood transplant"
      },
      {
        "code": "1",
        "description": "Monomorphic PTLD \r\n\r\n• PTLD WITH a specified histology (lymphoma, plasmacytoma, plasma cell myeloma"
      },
      {
        "code": "2",
        "description": "Classic Hodgkin lymphoma-PTLD type \r\n\r\nPTLD, Hodgkin like"
      },
      {
        "code": "4",
        "description": "PTLD not specified as monomorphic or Hodgkin lymphoma-PTLD type\r\n\r\n• WITH a specified histology (lymphoma, plasmacytoma, plasma cell myeloma)\r\n\r\n• Includes Burkitt type PTLD"
      },
      {
        "code": "8",
        "description": "Not applicable: Information not collected for this case  \r\n(If this item is required by your standard setter, use of code 8 will result in an edit error)"
      }
    ]
  },
