    "date_modified": "2022-05-27T07:24:13Z",
    "description": "This field is used to identify patients/tumors whose radiation treatment course was discontinued earlier than initially planned. That is the patients/tumors received fewer treatment fractions (sessions) than originally intended by the treating physician. This data item is required for CoC-accredited facilities as of cases diagnosed 01/01/2018 and later.",
    "rationale": "Currently, the total dose of radiation reflects what was actually delivered rather than what was intended. When a patient doesn’t complete a radiation course as initially intended this is typically commented on within the radiation end of treatment summary. By flagging these patients within the cancer registry database, these patients can be excluded from analyses attempting to describe adherence to radiation treatment guidelines or patterns of care analyses.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required",
    "seer_collect": "Required, when available",
    "cccr_collect": "No recommendation",
    "allowable_values": "00-07, 99",
    "allowed_codes": [
      {
        "code": "00",
        "description": "No radiation treatment"
      },
      {
        "code": "01",
        "description": "Radiation treatment completed as prescribed"
      },
      {
        "code": "02",
        "description": "Radiation treatment discontinued early - toxicity"
      },
      {
        "code": "03",
        "description": "Radiation treatment discontinued early - contraindicated due to other patient risk factors (comorbid conditions, advanced age, progression of tumor prior to planned radiation etc.)"
      },
      {
        "code": "04",
        "description": "Radiation treatment discontinued early - patient decision"
      },
      {
        "code": "05",
        "description": "Radiation discontinued early - family decision"
      },
      {
        "code": "06",
        "description": "Radiation discontinued early - patient expired"
      },
      {
        "code": "07",
        "description": "Radiation discontinued early - reason not documented"
      },
      {
        "code": "99",
        "description": "Unknown if radiation treatment discontinued; Unknown whether radiation therapy administered"
      }
    ]
  },
  {
    "item_number": "3190",
    "item_name": "Readm Same Hosp 30 Days",
    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "2003",
    "version_implemented": "10",
    "xml_naaccr_id": "readmSameHosp30Days",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Treatment-1st Course",
    "source_of_standard": "CoC",
    "date_created": "2011-11-09T09:47:21Z",
    "date_modified": "2022-05-27T07:24:10Z",
    "description": "Records a readmission to the same hospital within 30 days of discharge following hospitalization for surgical resection of the primary site for the same illness.",
    "rationale": "This data item provides information related to the quality of care. A patient may have a readmission related to the primary diagnosis on discharge if the length of stay was too short, and then needed to return due to problems or complications. A patient may also need to be readmitted if discharge planning and/or follow-up instructions were ineffective. It is important to distinguish a planned from an unplanned readmission, since a planned readmission is not an indicator of quality of care problems.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required",
    "seer_collect": "No recommendation",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "Readmission to the Same Hospital Within 30 Days of Surgical Discharge"
    ],
    "allowable_values": "0-3, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "No surgical procedure of the primary site was performed. Patient not readmitted to the same hospital within 30 days of discharge."
      },
      {
        "code": "1",
        "description": "Patient was surgically treated and was then readmitted to the same hospital within 30 days of being discharged. This readmission was unplanned."
      },
      {
        "code": "2",
        "description": "Patient was surgically treated and was then readmitted to the same hospital within 30 days of being discharged. This readmission was planned (chemotherapy port insertion, revision of colostomy, etc.)."
      },
      {
        "code": "3",
        "description": "Patient was surgically treated and, within 30 days of being discharged, had both a planned and an unplanned readmission to the same hospital."
      },
      {
        "code": "9",
        "description": "It is unknown whether surgery of the primary site was recommended or performed. It is unknown whether the patient was readmitted to the same hospital within 30 days of discharge. Death certificate only."
      }
    ]
  },
