  {
    "item_number": "339",
    "item_name": "RUCA 2000",
    "item_data_type": "mixed",
    "item_length": "1",
    "year_implemented": "2018",
    "version_implemented": "18",
    "xml_naaccr_id": "ruca2000",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Demographic",
    "source_of_standard": "NAACCR",
    "date_created": "2017-11-14T08:25:43Z",
    "date_modified": "2022-05-27T07:24:06Z",
    "description": "A measure of how accessible to an urban center a cancer patient''s census tract at diagnosis is based on the USDA identification of urban and rural commuting areas. The variable is a binomial-either in an urban commuting area or not. The measure indicates proximity to large urban centers and can be an indicator of access to oncology specialists and cancer treatment facilities. Collecting the variable with each decennial census allows for retrospective and cross-sectional epidemiologic analysis.",
    "rationale": "Studies have shown that residents of rural areas have lower screening rates, lower rates of follow-up of abnormal screening tests, higher late-stage diagnosis rates, and differences in cancer treatment patterns. Including tract-level indicators of rural-urban residence in the NAACCR data files will facilitate research in rural-urban disparities and allow researchers to control for rural-urban differences in model-based analysis of cancer risks and outcomes. Using these codes allows cancer registries to release the area-based measure instead of more sensitive information such as address or long/lat. The measure has been tested for uniqueness and the categories selected/aggregated so that identification of individual level census tracts is not possible as long as county is not known. Therefore, unless the researcher can scientifically defend the need for county, the county identifier will not be released in the same database.",
    "npcr_collect": "Derived",
    "coc_collect": "No recommendation",
    "seer_collect": "Derived",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "Rural Urban Commuting Area-Tract-level 2000"
    ],
    "code_note": "*Note*: This is a derived variable. Currently, the variable is derived during call for data. However, SAS code to derive the variable at the central registry variable for local use is available on the NAACCR website.",
    "allowable_values": "1, 2, 9",
    "allowed_codes": [
      {
        "code": "1",
        "description": "Urban commuting area-RUCA codes 1.0, 1.1, 2.0, 2.1, 3.0, 4.1, 5.1, 7.1, 8.1, and 10.1"
      },
      {
        "code": "2",
        "description": "Not an urban commuting area-All other RUCA codes except 99"
      },
      {
        "code": "9",
        "description": "Unknown or not applicable-census tract not available or RUCA code = 99"
      }
    ]
  },
