  {
    "item_number": "740",
    "item_name": "RX Hosp--DX/Stg Proc",
    "item_data_type": "digits",
    "item_length": "2",
    "xml_naaccr_id": "rxHospDxStgProc",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Hospital-Specific",
    "source_of_standard": "CoC",
    "date_created": "2011-11-09T09:47:21Z",
    "date_modified": "2022-05-27T07:24:12Z",
    "description": "Identifies the surgical procedure(s) performed in an effort to diagnose and/or stage disease at this facility.",
    "rationale": "This data item is used to track the use of surgical procedure resources that are not considered treatment.  \n  \nIf central registries wish to study the procedures performed at particular facilities, the facility-level fields must be used. The summary fields, conversely, combine information for all facilities that provide first course of treatment for the tumor. Facility-specific fields allow studies of detailed referral patterns and diagnostic/staging procedures by type of healthcare setting. Knowing what part of the diagnostic or staging process was performed at a particular facility also helps resolve consolidation issues.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required",
    "seer_collect": "No recommendation",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "Non Cancer-Directed Surgery at this Facility (CoC)",
      "Surgical Diagnostic & Staging Procedure at this Facility (1996-2002)",
      "RX Hosp--DX/Stg/Pall Proc"
    ],
    "format": "Right justified, zero filled",
    "code_note": "*Note*: This item has been used for tumors diagnosed in 1996 and later. For cases diagnosed before 1996, this item may have been converted from the *DAM*, and cases with surgery would have been converted to 09 in this field. For cases diagnosed between 1996 and 2002, this field may have described palliative care according to coding rules in *ROADS*. For tumors diagnosed on or after January 1, 2003, palliative care is coded in a new field RX Hosp--Palliative Proc [3280].",
    "code_description": "Refer to the most recent version of *STORE* for additional instructions.",
    "allowable_values": "00-07, 09",
    "allowed_codes": [
      {
        "code": "00",
        "description": "No surgical diagnostic or staging procedure was performed."
      },
      {
        "code": "01",
        "description": "A biopsy (incisional, needle, or aspiration) was done to a site other than the primary site. No exploratory procedure was done."
      },
      {
        "code": "02",
        "description": "A biopsy (incisional, needle, or aspiration) was done of the primary site or biopsy of a lymph node was done to diagnose or stage lymphoma."
      },
      {
        "code": "03",
        "description": "A surgical exploration only. The patient was not biopsied or treated during the procedure."
      },
      {
        "code": "04",
        "description": "A surgical procedure with a bypass was performed, but no biopsy was done."
      },
      {
        "code": "05",
        "description": "An exploratory procedure was performed, and a biopsy of either the primary site or another site was done."
      },
      {
        "code": "06",
        "description": "A bypass procedure was performed, and a biopsy of either the primary site or another site was done."
      },
      {
        "code": "07",
        "description": "A procedure was done, but the type of procedure is unknown."
      },
      {
        "code": "09",
        "description": "No information about whether a diagnostic or staging procedure was performed."
      }
    ]
  },
