    "section": "Hospital-Specific",
    "source_of_standard": "CoC",
    "date_created": "2011-11-09T09:47:21Z",
    "date_modified": "2022-05-27T07:24:11Z",
    "description": "Identifies treatment given at this facility that cannot be defined as surgery, radiation, or systemic therapy according to the defined data items in this manual. Treatment for reportable hematopoietic diseases can be supportive care, observation, or any treatment that does not meet the usual definition in which treatment modifies, controls, removes, or destroys proliferating cancer tissue. Supportive care such as phlebotomy, transfusions, or aspirin may be recorded for hematopoietic diseases ONLY.",
    "rationale": "Information on other therapy is used to describe treatment practices and evaluate quality of care. If central registries wish to study the treatment given at particular facilities, the facility-level treatment fields must be used. The summary treatment fields, conversely, combine information for all reporting facilities that provide first course of treatment for the tumor. Facility-specific fields allow studies of detailed referral patterns and treatment by type of healthcare setting. Knowing what part of the treatment was given at a particular facility also helps resolve consolidation issues.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required",
    "seer_collect": "Required",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "Other Treatment at this Facility (CoC)"
    ],
    "allowable_values": "0-3, 6-9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "None; all cancer treatment was coded in other treatment fields. Patient received no cancer treatment. Diagnosed at autopsy."
      },
      {
        "code": "1",
        "description": "Cancer treatment that cannot be assigned to specified treatment data items."
      },
      {
        "code": "2",
        "description": "Other-Experimental; this code is not defined. It may be used to record participation in institution-based clinical trials."
      },
      {
        "code": "3",
        "description": "Patient is involved in a double-blind clinical trial. Code the treatment actually administered when the double-blind trial code is broken."
      },
      {
        "code": "6",
        "description": "Other unproven; Cancer treatments administered by nonmedical personnel."
      },
      {
        "code": "7",
        "description": "Refusal; other treatment was not administered. Treatment listed in code 1, 2 or 3 was recommended by the patient''s physician but was refused by the patient or the patient''s family or guardian. The refusal was noted in the patient record."
      },
      {
        "code": "8",
        "description": "Recommended, unknown if administered; other treatment was recommended, but it is unknown whether it was administered."
      },
      {
        "code": "9",
        "description": "It is unknown whether other treatment was recommended or administered because it is not stated in the patient record. Death certificate only case."
      }
    ]
  },
