    "description": "Identifies care provided at the reporting facility in an effort to palliate or alleviate symptoms. Palliative procedures may include surgery, radiation therapy, systemic therapy (chemotherapy, hormone therapy, or other systemic drugs), and/or pain management.",
    "rationale": "This data item allows reporting facilities to track care that is considered palliative rather than diagnostic or curative in intent. If central registries wish to study types of palliative care given at particular facilities, the facility-level fields must be used. Facility-specific fields allow studies of detailed referral patterns and treatment by type of healthcare setting. Knowing what palliative procedures and care was performed at a particular facility also helps resolve consolidation issues.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required",
    "seer_collect": "No recommendation",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "Palliative Care at this Facility",
      "Palliative Procedure at this Facility"
    ],
    "allowable_values": "0-7, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "No palliative care provided. Diagnosed at autopsy"
      },
      {
        "code": "1",
        "description": "Surgery (which may involve a bypass procedure) performed to alleviate symptoms, but no attempt to diagnose, stage, or treat the tumor is made."
      },
      {
        "code": "2",
        "description": "Radiation therapy given to alleviate symptoms, but no attempt to produce cure is made."
      },
      {
        "code": "3",
        "description": "Chemotherapy, hormone therapy, or other systemic drugs given to alleviate symptoms without curative intent."
      },
      {
        "code": "4",
        "description": "Patient received or was referred for pain management only."
      },
      {
        "code": "5",
        "description": "Any combination of codes 1, 2, and/or 3 without code 4."
      },
      {
        "code": "6",
        "description": "Any combination of codes 1, 2, and/or 3 with code 4."
      },
      {
        "code": "7",
        "description": "Palliative care was performed or recommended, but no information on the type of procedure is available in the patient record."
      },
      {
        "code": "9",
        "description": "Unknown if palliative care was performed or recommended. Not stated in patient record."
      }
    ]
  },
