    "date_modified": "2022-05-27T07:24:10Z",
    "description": "Identifies any care provided in an effort to palliate or alleviate symptoms. Palliative care is performed to relieve symptoms and may include surgery, radiation therapy, systemic therapy (chemotherapy, hormone therapy, or other systemic drugs), and/or pain management therapy.",
    "rationale": "This data item allows reporting facilities to track care that is considered palliative rather than diagnostic or curative intent.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required",
    "seer_collect": "No recommendation",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "Palliative Procedure",
      "Palliative Care"
    ],
    "allowable_values": "0-7, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "No palliative care provided; diagnosed at autopsy"
      },
      {
        "code": "1",
        "description": "Surgery (which may involve a bypass procedure) to alleviate symptoms, but no attempt to diagnose, stage, or treat the primary tumor is made"
      },
      {
        "code": "2",
        "description": "Radiation therapy to alleviate symptoms, but no attempt to diagnose, stage, or treat the primary tumor is made"
      },
      {
        "code": "3",
        "description": "Chemotherapy, hormone therapy, or other systemic drugs to alleviate symptoms, but no attempt to diagnose, stage, or treat the primary tumor is made"
      },
      {
        "code": "4",
        "description": "Patient received or was referred for pain management therapy with no other palliative care"
      },
      {
        "code": "5",
        "description": "Any combination of codes 1, 2, and/or 3 without code 4"
      },
      {
        "code": "6",
        "description": "Any combination of codes 1, 2, and/or 3 with code 4"
      },
      {
        "code": "7",
        "description": "Palliative care was performed or referred, but no information on the type of procedure is available in the patient record"
      },
      {
        "code": "9",
        "description": "Unknown if palliative care was performed or referred; not stated in patient record"
      }
    ]
  },
