    "section": "Treatment-1st Course",
    "source_of_standard": "SEER/CoC",
    "date_created": "2011-11-09T09:47:21Z",
    "date_modified": "2022-05-27T07:24:11Z",
    "description": "Describes the removal, biopsy or aspiration of regional lymph node(s) at the time of surgery of the primary site or during a separate surgical event at all facilities.",
    "rationale": "In evaluating quality-of-care and treatment practices it is important to identify the removal, biopsy, or aspiration of regional lymph node(s) at the time of surgery of the primary site or during a separate surgical event.",
    "npcr_collect": "Required",
    "coc_collect": "Required",
    "seer_collect": "Required",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "Scope of Regional Lymph Node Surgery (SEER/CoC)"
    ],
    "code_note": "*Note:* One important use of registry data is the tracking of treatment patterns over time. To compare contemporary treatment to previously published treatment based on former codes, or to data unmodified from pre-1998 definitions, the ability to differentiate surgeries in which four or more regional lymph nodes are removed is desirable. However, it is very important to note that the distinction between codes 4 and 5 is made to permit comparison of current surgical procedures with procedures coded in the past when the removal of fewer than 4 nodes was not reflected in surgery codes. It is not intended to reflect clinical significance when applied to a particular surgical procedure. It is important to avoid inferring, by data presentation or other methods, that one category is preferable to another within the intent of these items.",
    "code_description": "Refer to the most recent versions of *STORE* and the *SEER Program Code Manual* for instructions that should be applied to all surgically treated cases for all types of cancers. The treatment of breast and skin cancers are where the distinction between sentinel lymph node biopsies (SLNBx) and more extensive dissection of regional lymph nodes is most frequently encountered. For all other sites, non-sentinel regional node dissections are typical, and codes 2, 6 and 7 are infrequently used",
    "allowable_values": "0-7, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "None"
      },
      {
        "code": "1",
        "description": "Biopsy or aspiration of regional lymph node, NOS"
      },
      {
        "code": "2",
        "description": "Sentinel lymph node biopsy"
      },
      {
        "code": "3",
        "description": "Number of regional lymph nodes removed unknown, not stated; regional lymph nodes removed, NOS"
      },
      {
        "code": "4",
        "description": "1 to 3 regional lymph nodes removed"
      },
      {
        "code": "5",
        "description": "4 or more regional lymph nodes removed"
      },
      {
        "code": "6",
        "description": "Sentinel node biopsy and code 3, 4, or 5 at same time or timing not noted"
      },
      {
        "code": "7",
        "description": "Sentinel node biopsy and code 3, 4, or 5 at different times"
      },
      {
        "code": "9",
        "description": "Unknown or not applicable"
      }
    ]
  },
