    "date_modified": "2022-05-27T07:24:12Z",
    "description": "Identifies systemic therapeutic procedures administered as part of the first course of treatment at this and all other facilities. If none of these procedures were administered then this item records the reason they were not performed. These include bone marrow transplants, stem cell harvests, surgical and/or radiation endocrine therapy.",
    "rationale": "This data item allows the evaluation of patterns of treatment, which involve the alteration of the immune system or change the patient’s response to tumor cells but do not involve the administration of antineoplastic agents.",
    "npcr_collect": "Required",
    "coc_collect": "Required",
    "seer_collect": "Required",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "Hematologic Transplant and Endocrine Procedures"
    ],
    "format": "Right justified, zero filled",
    "code_description": "Refer to the most recent version of *STORE* for additional instructions.",
    "allowable_values": "00, 10-12, 20, 30, 40, 82, 85-88, 99",
    "allowed_codes": [
      {
        "code": "00",
        "description": "No transplant procedure or endocrine therapy was administered as part of first course therapy; diagnosed at autopsy"
      },
      {
        "code": "10",
        "description": "Bone marrow transplant procedure was administered, but the type was not specified."
      },
      {
        "code": "11",
        "description": "Bone marrow transplant-autologous"
      },
      {
        "code": "12",
        "description": "Bone marrow transplant-allogeneic"
      },
      {
        "code": "20",
        "description": "Stem cell harvest and infusion"
      },
      {
        "code": "30",
        "description": "Endocrine surgery and/or endocrine radiation therapy."
      },
      {
        "code": "40",
        "description": "Combination of endocrine surgery and/or radiation with a transplant procedure. (combination of codes 30 and 10, 11, 12 or 20)."
      },
      {
        "code": "82",
        "description": "Hematologic transplant and/or endocrine surgery/radiation was not recommended/administered because it was contraindicated due to patient risk factors (i.e., comorbid conditions, advanced age)."
      },
      {
        "code": "85",
        "description": "Hematologic transplant and/or endocrine surgery/radiation was not administered because the patient died prior to planned or recommended therapy."
      },
      {
        "code": "86",
        "description": "Hematologic transplant and/or endocrine surgery/radiation was not administered. It was recommended by the patient''s physician, but was not administered as part of first-course therapy. No reason was stated in the patient record."
      },
      {
        "code": "87",
        "description": "Hematologic transplant and/or endocrine surgery/radiation was not administered; it was recommended by the patient''s physician, but this treatment was refused by the patient, the patient''s family member, or the patient''s guardian; refusal noted in patient record"
      },
      {
        "code": "88",
        "description": "Hematologic transplant and/or endocrine surgery/radiation was recommended, but it is unknown if it was administered"
      },
      {
        "code": "99",
        "description": "It is unknown whether hematologic transplant and/or endocrine surgery/radiation was recommended or administered because it is not stated in patient record; death certificate-only cases"
      }
    ]
