    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2017-11-14T06:34:26Z",
    "date_modified": "2022-05-27T07:24:09Z",
    "description": "Sarcomatoid features: present or absent and percentage refers to the observation of sheets and fascicles of malignant spindle cells in a kidney tumor which can occur across all histologic subtypes. The percentage of sarcomatoid component has been shown to correlate with cancer-specific mortality.",
    "rationale": "Sarcomatoid features for Kidney is a Registry Data Collection Variable in AJCC. It was previously collected as Kidney, CS SSF #4.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "No recommendation",
    "code_note": "Each Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "000, 001-100, R01, R02, R03, R04, R05, XX5, XX6, XX7, XX8, XX9",
    "allowed_codes": [
      {
        "code": "000",
        "description": "Sarcomatoid features not present/not identified"
      },
      {
        "code": "000-100",
        "description": "Sarcomatoid features 1-100%"
      },
      {
        "code": "R01",
        "description": "Sarcomatoid features stated as less than 10%"
      },
      {
        "code": "R02",
        "description": "Sarcomatoid features stated as range 10%-30% present"
      },
      {
        "code": "R03",
        "description": "Sarcomatoid features stated as a range 31% to 50% present"
      },
      {
        "code": "R04",
        "description": "Sarcomatoid features stated as a range 51% to 80% present"
      },
      {
        "code": "R05",
        "description": "Sarcomatoid features stated as greater than 80%"
      },
      {
        "code": "XX5",
        "description": "Sarcomatoid features present from metastatic site only AND  \n Sarcomatoid features not present in primary site, or unknown if present"
      },
      {
        "code": "XX6",
        "description": "Sarcomatoid features present, percentage unknown"
      },
      {
        "code": "XX7",
        "description": "Not applicable: Not a renal cell carcinoma morphology"
      },
      {
        "code": "XX8",
        "description": "Not applicable: Information not collected for this case  \n (If this information is required by your standard setter, use of code XX8 may result in an edit error.)"
      },
      {
        "code": "XX9",
        "description": "Not documented in medical record  \n Sarcomatoid features not assessed or unknown if assessed  \n No surgical resection of primary site is performed"
      }
    ]
  },
