      },
      {
        "code": "G00.0 - P96.9",
        "description": "diseases of the nervous system, eye, ear, skin, circulatory, respiratory, and digestive , musculoskeletal, genitourinary systems, pregnancy, childbirth and perinatal conditions"
      },
      {
        "code": "R00.0 - S99.929",
        "description": "symptoms, signs and abnormal clinical and lab findings"
      },
      {
        "code": "T36.0 - T50.996",
