  {
    "item_number": "760",
    "item_name": "SEER Summary Stage 1977",
    "item_data_type": "digits",
    "item_length": "1",
    "xml_naaccr_id": "seerSummaryStage1977",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "SEER",
    "date_created": "2011-11-09T14:47:21Z",
    "date_modified": "2023-05-11T15:22:24.195162Z",
    "description": "Code for summary stage at the initial diagnosis or treatment of the reportable tumor. This has traditionally been used by central registries to monitor time trends. For hospital registries, CoC requires its use in the absence of a defined AJCC classification. For site-specific definitions of categories, see the SEER Summary Staging Guide.\r\n\r\nSEER Summary Stage 1977 is limited to information available within 2 months of the date of diagnosis. NAACCR approved extension of this time period to 4 months for prostate tumors diagnosed beginning January 1, 1995.",
    "rationale": "Stage information is important when evaluating the effects of cancer control programs. It is crucial for understanding whether changes over time in incidence rates or outcomes are due to earlier detection of the cancers. In addition, cancer treatment cannot be studied without knowing the stage at diagnosis.\r\n\r\nTo study historical trends in stage, the coding system must be relatively unchanged (stable) over time. AJCC’s TNM system is updated periodically to maintain clinical relevance with changes in diagnosis and treatment. The surveillance registries often rely on the Summary Stage, which they consider to be more “stable.” Summary Stage has been in widespread use, either as the primary staging scheme or a secondary scheme, in most central and hospital registries since 1977.",
    "npcr_collect": "Historically collected and currently transmitted",
    "coc_collect": "Historically collected and currently transmitted",
    "seer_collect": "No recommendation",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "General Summary Stage (SEER/CoC)"
    ],
    "code_note": "_Note:_ Code 8 has been added in Version 10.1 to be used when there is not an applicable code to reflect stage (e.g., benign brain, borderline ovarian). \r\n\r\n_Note:_ See also the item Derived SS1977 \\[3010\\] for the value of SEER Summary Stage 1977 as generated by the Collaborative Staging algorithm. \r\n\r\n**Clarification of NAACCR and NPCR Required Status**\r\n\r\nSummary stage is required. The correct data item to use (and corresponding code manual) is determined by the year in which the cancer was diagnosed. Tumors diagnosed on or after January 1, 2004, should be assigned a summary stage based upon the Collaborative Stage data item algorithms and retained in Derived SS2000 \\[3020\\]. Tumors diagnosed on or after January 1, 2001, should be assigned a summary stage according to the SEER _Summary Staging Manual 2000_, and the code should be reported in SEER Summary Stage 2000 \\[759\\]. Tumors diagnosed before January 1, 2001, should be assigned a summary stage according to _SEER Summary Stage Guide 1977_, and the code should be reported in SEER Summary Stage 1977 \\[760\\].",
    "allowable_values": "0-5, 7, 8, 9",
    "allowed_codes": [
      {
        "code": "9",
        "description": "Unstaged"
      },
      {
        "code": "0",
        "description": "*In situ*"
      },
      {
        "code": "1",
        "description": "Localized"
      },
      {
        "code": "2",
        "description": "Regional, direct extension only"
      },
      {
        "code": "3",
        "description": "Regional, regional lymph nodes only"
      },
      {
        "code": "4",
        "description": "Regional, direct extension and regional lymph nodes"
      },
      {
        "code": "5",
        "description": "Regional, NOS"
      },
      {
        "code": "7",
        "description": "Distant"
      },
      {
        "code": "8",
        "description": "Not applicable"
      }
    ]
  },
