    "description": "Records the total number of lymph nodes sampled during the sentinel node biopsy and examined by the pathologist. This data item is required for CoC-accredited facilities as of cases diagnosed 01/01/2018 and later. **This data item is required for breast and melanoma cases only.** ",
    "rationale": "It is a known fact that sentinel lymph node biopsies have been under-reported. Additionally, the timing and results of sentinel lymph node biopsy procedures are used in quality of care measures. This data item can be used to more accurately assess the number of lymph nodes biopsied during the sentinel node biopsy procedure separate from the number of lymph nodes dissected during additional subsequent regional node procedures.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "No recommendation",
    "format": "Right justified, zero filled",
    "allowable_values": "00-90, 95, 98, 99",
    "allowed_codes": [
      {
        "code": "00",
        "description": "No sentinel nodes were examined"
      },
      {
        "code": "01-90",
        "description": "Sentinel nodes were examined (code the exact number of sentinel lymph nodes examined)"
      },
      {
        "code": "95",
        "description": "No sentinel nodes were removed, but aspiration of sentinel node(s) was performed"
      },
      {
        "code": "98",
        "description": "Sentinel lymph nodes were biopsied, but the number is unknown"
      },
      {
        "code": "99",
        "description": "It is unknown whether sentinel nodes were examined; not stated in patient record"
      }
    ]
  },
