        "description": "Sentinel nodes are positive (code exact number of nodes positive)"
      },
      {
        "code": "95",
        "description": "Positive aspiration of sentinel lymph node(s) was performed"
      },
      {
        "code": "97",
        "description": "Positive sentinel nodes are documented, but the number is unspecified; For breast ONLY: SLN and RLND occurred during the same procedure"
      },
      {
        "code": "98",
        "description": "No sentinel nodes were biopsied"
      },
      {
        "code": "99",
        "description": "It is unknown whether sentinel nodes are positive; not applicable; not stated in patient record"
      }
    ]
