  {
    "item_number": "764",
    "item_name": "Summary Stage 2018",
    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "2018",
    "version_implemented": "16",
    "xml_naaccr_id": "summaryStage2018",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "SEER",
    "date_created": "2015-08-22T16:50:30Z",
    "date_modified": "2023-05-11T19:24:11.614987Z",
    "description": "This item stores the directly assigned Summary Stage 2018. Effective for cases diagnosed 1/1/2018+.",
    "general_notes": "_Note_: This data item was included in Standards Volume II, Version 16; however, it was not implemented until 2018.",
    "rationale": "The SEER program has collected staging information on cases since its inception in 1973. Summary Stage groups cases into broad categories of in situ, local, regional, and distant. Summary Stage can be used to evaluate disease spread at diagnosis, treatment patterns and outcomes over time.",
    "npcr_collect": "Required",
    "coc_collect": "No recommendation",
    "seer_collect": "Required, when available",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "Directly Assigned SS2018"
    ],
    "code_note": "\\*Applicable for the following SS2018 chapters: Brain, CNS Other, Intracranial Gland.\r\n\r\n_Note_: For SS2018, code 5 for “Regional, NOS” can no longer be coded. Code 5 (Regional, NOS) is still applicable.",
    "allowable_values": "0-4, 7-9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "In situ"
      },
      {
        "code": "1",
        "description": "Localized only"
      },
      {
        "code": "2",
        "description": "Regional by direct extension only"
      },
      {
        "code": "3",
        "description": "Regional lymph nodes only"
      },
      {
        "code": "4",
        "description": "Regional by BOTH direct extension AND lymph node involvement"
      },
      {
        "code": "7",
        "description": "Distant site(s)/node(s) involved"
      },
      {
        "code": "8",
        "description": "Benign/borderline\\*"
      },
      {
        "code": "9",
        "description": "Unknown if extension or metastasis (unstaged, unknown, or unspecified)  \n Death certificate only case"
      }
    ]
  },
