    "description": "Thrombocytopenia is defined by a deficiency of platelets in the blood. In staging of Chronic Lymphocytic Leukemia/Small Lymphocytic Lymphoma (CLL/SLL), thrombocytopenia is defined as Platelets (Plt) less than 100,000/μL.",
    "rationale": "Thrombocytopenia is a prognostic factor required for staging of Chronic Lymphocytic Leukemia/Small Lymphocytic Lymphoma (CLL/SLL) in AJCC 8th edition, Chapter 79 _Hodgkin and Non-Hodgkin Lymphomas_.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "Required, site specific; when available",
    "code_note": "Each Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "0, 1, 5, 6, 7, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Thrombocytopenia not present  \r\nPlatelets (Plt) = 100,000/µL\r\n\r\nPhysician states Rai Stage 0-III"
      },
      {
        "code": "1",
        "description": "Thrombocytopenia present  \r\nPlatelets (Plt) \\< 100,000/µL"
      },
      {
        "code": "5",
        "description": "Not applicable: Primary site is not C421"
      },
      {
        "code": "6",
        "description": "Lab value unknown, physician states thrombocytopenia is present  \n  \n Physician states Rai Stage IV"
      },
      {
        "code": "7",
        "description": "Test ordered, results not in chart"
      },
      {
        "code": "9",
        "description": "Not documented in medical record  \n Thrombocytopenia not assessed or unknown if assessed  \n No Rai stage is documented in the record and there is no documentation of thrombocytopenia"
      }
    ]
  },
