    "date_modified": "2023-05-28T15:28:41.788571Z",
    "description": "Identifies the AJCC clinical stage (prefix/suffix) descriptor as recorded by the physician. AJCC stage descriptors identify special cases that need separate data analysis. The descriptors are adjuncts to and do not change the stage group.\r\n\r\nPathologic and clinical stage data are given three separate areas in the NAACCR Data Exchange Record Layout. CoC defines a descriptor and “Staged By” item for each of these three areas.",
    "rationale": "CoC requires that AJCC TNM staging be used in its approved cancer programs. AJCC developed its staging system for evaluating trends in the treatment and control of cancer. This staging is used by physicians to estimate prognosis, to plan treatment, to evaluate new types of therapy, to analyze outcome, to design follow-up strategies, and to assess early detection results.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Historically collected and currently transmitted",
    "seer_collect": "Historically collected and currently transmitted",
    "cccr_collect": "No recommendation",
    "alternate_names": [
      "Clinical Stage (Prefix/Suffix) Descriptor (CoC)"
    ],
    "allowable_values": "0-3, 5, 9, blank",
    "allowed_codes": [
      {
        "code": "0",
        "description": "None"
      },
      {
        "code": "1",
        "description": "E (Extranodal, lymphomas only)"
      },
      {
        "code": "2",
        "description": "S (Spleen, lymphomas only)"
      },
      {
        "code": "3",
        "description": "M (Multiple primary tumors in a single site)"
      },
      {
        "code": "5",
        "description": "E & S (Extranodal and spleen, lymphomas only)"
      },
      {
        "code": "9",
        "description": "Unknown, not stated in patient record"
      },
      {
        "code": "blank",
        "description": "Field not coded"
      }
    ]
  },
