  {
    "item_number": "344",
    "item_name": "Tobacco Use Smoking Status",
    "item_data_type": "text",
    "item_length": "1",
    "year_implemented": "2022",
    "version_implemented": "22",
    "xml_naaccr_id": "tobaccoUseSmokingStatus",
    "xml_parent_id": "Tumor",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Demographic",
    "source_of_standard": "NPCR",
    "date_created": "2021-06-05T09:36:00Z",
    "date_modified": "2024-05-02T00:39:39.9983Z",
    "description": "Tobacco Use Smoking Status indicates the patient’s past or current smoking use of tobacco (cigarette, cigar and/or pipe).",
    "rationale": "Reliable registry-based tobacco use data will help public health planners and clinicians target and assess tobacco control efforts. Tobacco use data at diagnosis may help health professionals better understand how tobacco use impacts cancer outcomes, prognosis, and effectiveness of treatment. Smoking status may be a useful covariate risk factor for cancer cluster investigations.",
    "npcr_collect": "Required, when available",
    "coc_collect": "Required",
    "seer_collect": "Required, when available",
    "cccr_collect": "No recommendation",
    "code_note": "*   Record cigarette, cigar, and/or pipe use only. Tobacco Use Smoking Status does not include marijuana, chewing tobacco, e-cigarettes, or vaping devices.\r\n*   Tobacco smoking history can be obtained from sections such as the Nursing Interview Guide, Flow Chart, Vital Stats or Nursing Assessment section, or other available sources from the patient''s hospital medical record or physician office record.\r\n*   Use code 1 if there is evidence in the medical record that the patient quit smoking within 30 days prior to diagnosis. The 30 days prior information is intended to differentiate patients who may have quit recently due to symptoms that led to a cancer diagnosis. \r\n*   Use code 2 if medical record indicates patient smoked tobacco in the past, but does not smoke now. Patient must have quit 31 or more days prior to cancer diagnosis to be coded as ‘Former smoker.’\r\n*   Use code 3 if it cannot be determined whether the patient currently smokes or formerly smoked. For example, the medical record only indicates “Yes” for smoking without further information.\r\n*   Use code 9 (Unknown if ever smoked) rather than code 0 (Never smoker), if\r\n    *   the medical record only indicates “No” for tobacco use;\r\n    *   smoking status is not stated or provided; or\r\n    *   the method (cigarette, pipe, cigar) used cannot be verified in the chart.\r\n*   This data item can be left blank for cases diagnosed prior to 1/1/2022.",
    "allowable_values": "0-3, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Never smoker"
      },
      {
        "code": "1",
        "description": "Current smoker"
      },
      {
        "code": "2",
        "description": "Former smoker"
      },
      {
        "code": "3",
        "description": "Smoker, current status unknown"
      },
      {
        "code": "9",
        "description": "Unknown if ever smoked"
      }
    ]
  },
