    ],
    "section": "Stage/Prognostic Factors",
    "source_of_standard": "NAACCR",
    "date_created": "2017-11-14T16:11:31Z",
    "date_modified": "2023-05-12T06:52:16.395714Z",
    "description": "Visceral and Parietal Pleural Invasion is defined as invasion beyond the elastic layer or to the surface of the visceral pleura.",
    "rationale": "Visceral and Parietal Pleural Invasion (previously called \"pleural/elastic layer invasion (PL)\") is a Registry Data Collection Variable for AJCC. This data item was previously collected for Lung, SSF# 2.",
    "npcr_collect": "No recommendation",
    "coc_collect": "Required, site specific",
    "seer_collect": "Required, site specific",
    "cccr_collect": "No recommendation",
    "code_note": "Each Site-Specific Data Item (SSDI) applies only to selected primary sites, histologies, and years of diagnosis. Depending on applicability and standard-setter requirements, SSDIs may be left blank.",
    "allowable_values": "0, 4-6, 8, 9",
    "allowed_codes": [
      {
        "code": "0",
        "description": "No evidence of visceral pleural invasion identified  \n Tumor does not completely traverse the elastic layer of the pleura  \n Stated as PL0"
      },
      {
        "code": "4",
        "description": "Invasion of visceral pleural present, NOS  \n Stated as PL1 or PL2"
      },
      {
        "code": "5",
        "description": "Tumor invades into or through the parietal pleural OR chest wall  \r\nStated as PL3\r\n\r\nConversions that will be implemented:\r\n\r\n**Code 1 cases:** Now code 4\r\n\r\n  \r\n**Code 2 cases:** Now code 4\r\n\r\n  \r\n**Code 3 cases:** Now code 5"
      },
      {
        "code": "6",
        "description": "Tumor extends to pleura, NOS; not stated if visceral or parietal"
      },
      {
        "code": "8",
        "description": "Not applicable: Information not collected for this case  \n If this item is required by your standard setter, use of code 8 will result in an edit error.)"
      },
      {
        "code": "9",
        "description": "Not documented in medical record  \n No surgical resection of primary site is performed  \n Visceral Pleural Invasion not assessed or unknown if assessed or cannot be determined"
      }
    ]
  },
