  {
    "item_number": "1762",
    "item_name": "Vital Status Recode",
    "item_data_type": "digits",
    "item_length": "1",
    "year_implemented": "2018",
    "version_implemented": "18",
    "xml_naaccr_id": "vitalStatusRecode",
    "xml_parent_id": "Patient",
    "record_types": [
      "A",
      "C",
      "I",
      "M"
    ],
    "section": "Follow-up/Recurrence/Death",
    "source_of_standard": "NAACCR",
    "date_created": "2017-11-14T16:05:56Z",
    "date_modified": "2022-05-27T07:24:10Z",
    "description": "This variables is akin to Vital Status [1760], with the exception that any patient that dies after the follow-up cut-off date is recoded to alive as of the cut-off date. This variable is used as part of the algorithm for calculating the survival time recode variables (NAACCR items 1782-1788) and is used for survival, prevalence, and multiple primary – standardized incidence ratio analyses in SEER\\*Stat. This recode is necessary to conduct survival and prevalence analyses outside of SEER\\*Stat using other statistical software.",
    "rationale": "These changes will benefit the cancer surveillance community by facilitating the application of standard methods for survival analysis. Beginning with data collected in the November 2014 call for data, NAACCR has published  *Cancer in North America Volume 4: Cancer Survival in the United States and Canada*, which provides cancer survival estimates on a wider population than was previously available. However, at present IMS must pre-process the datasets that are included in the NAACCR survival dataset to calculate the four  standard data items, SEER Cause Specific COD [1914], SEER Other COD [1915], Record Number Recode [1775], and Vital Status Recode [1762]. For registries that do not submit cause of death information to NAACCR, it is not possible to calculate the ''SEER cause-specific death classification'' or ''SEER other cause of death classification'' variables. The 4 new data items will assist individual registries in performing survival analyses using their own data.",
    "npcr_collect": "Derived",
    "coc_collect": "No recommendation",
    "seer_collect": "Derived",
    "cccr_collect": "No recommendation",
    "allowable_values": "0, 1",
    "allowed_codes": [
      {
        "code": "0",
        "description": "Dead as of study cutoff date"
      },
      {
        "code": "1",
        "description": "Alive as of study cutoff date"
      }
    ]
  },
