DECLARE @itemsJsonFileOnServer NVARCHAR(4000) = NULL; -- e.g. N'/var/opt/mssql/data/items.json' or N'C:\temp\items.json'

IF @itemsJson IS NULL AND @itemsJsonFileOnServer IS NOT NULL
BEGIN
	DECLARE @loadSql NVARCHAR(MAX) =
		N'SELECT @jsonOut = BulkColumn FROM OPENROWSET(BULK '''
		+ REPLACE(@itemsJsonFileOnServer, '''', '''''')
		+ N''', SINGLE_CLOB) AS src;';

	EXEC sys.sp_executesql
		@loadSql,
		N'@jsonOut NVARCHAR(MAX) OUTPUT',
		@jsonOut = @itemsJson OUTPUT;
END;

/*
NAACCR -> OMOP concept loader (inlined from tmp/insert_naaccr_items_into_concept.sql)
*/

IF @itemsJson IS NULL OR TRY_CONVERT(NVARCHAR(MAX), @itemsJson) IS NULL
BEGIN
	THROW 50000, 'Expected @itemsJson NVARCHAR(MAX) containing a JSON array.', 1;
END;

IF ISJSON(@itemsJson) <> 1
BEGIN
	THROW 50000, 'Expected @itemsJson to be valid JSON.', 1;
END;

BEGIN TRANSACTION;

IF OBJECT_ID('tempdb..#items') IS NOT NULL DROP TABLE #items;

CREATE TABLE #items (
	item_number        NVARCHAR(50)  NULL,
	item_name          NVARCHAR(255) NOT NULL,
	item_data_type     NVARCHAR(100) NOT NULL,
	section            NVARCHAR(255) NOT NULL,
	xml_naaccr_id      NVARCHAR(100) NULL,
	xml_parent_id      NVARCHAR(100) NULL,
	date_created       NVARCHAR(50)  NULL,
  date_modified      NVARCHAR(50)  NULL,
  year_retired       NVARCHAR(50)  NULL
);

DECLARE @placeholder_item_name NVARCHAR(255) = N'UNKNOWN_ITEM_NAME';
DECLARE @placeholder_item_data_type NVARCHAR(100) = N'UNKNOWN_ITEM_DATA_TYPE';
DECLARE @placeholder_section NVARCHAR(255) = N'UNKNOWN_SECTION';

INSERT INTO #items (
	item_number,
	item_name,
	item_data_type,
	section,
	xml_naaccr_id,
	xml_parent_id,
	date_created,
  date_modified,
  year_retired
)
SELECT
	JSON_VALUE(j.[value], '$.item_number') AS item_number,
  COALESCE(NULLIF(LTRIM(RTRIM(JSON_VALUE(j.[value], '$.item_name'))), N''), @placeholder_item_name) AS item_name,
  COALESCE(NULLIF(LTRIM(RTRIM(JSON_VALUE(j.[value], '$.item_data_type'))), N''), @placeholder_item_data_type) AS item_data_type,
  COALESCE(NULLIF(LTRIM(RTRIM(JSON_VALUE(j.[value], '$.section'))), N''), @placeholder_section) AS section,
	JSON_VALUE(j.[value], '$.xml_naaccr_id') AS xml_naaccr_id,
	JSON_VALUE(j.[value], '$.xml_parent_id') AS xml_parent_id,
	JSON_VALUE(j.[value], '$.date_created') AS date_created,
  JSON_VALUE(j.[value], '$.date_modified') AS date_modified,
  JSON_VALUE(j.[value], '$.year_retired') AS year_retired
FROM OPENJSON(@itemsJson) AS j;

DECLARE @placeholderCount INT = (
  SELECT COUNT(*)
  FROM #items
  WHERE item_name = @placeholder_item_name
     OR item_data_type = @placeholder_item_data_type
     OR section = @placeholder_section
);

IF @placeholderCount > 0
BEGIN
  PRINT CONCAT('Warning: ', @placeholderCount, ' item(s) had missing/blank item_name, item_data_type, or section; placeholders were applied.');
END;

IF OBJECT_ID('tempdb..#derived') IS NOT NULL DROP TABLE #derived;

CREATE TABLE #derived (
	row_id            INT IDENTITY(1,1) NOT NULL,
	item_number       NVARCHAR(50)  NULL,
	item_name         NVARCHAR(255) NOT NULL,
	item_data_type    NVARCHAR(100) NOT NULL,
	section           NVARCHAR(255) NOT NULL,
	xml_naaccr_id     NVARCHAR(100) NULL,
	xml_parent_id     NVARCHAR(100) NULL,
	date_created      NVARCHAR(50)  NULL,
	date_modified     NVARCHAR(50)  NULL,
  year_retired      NVARCHAR(50)  NULL,
	vocabulary_id     VARCHAR(20)   NOT NULL,
	domain_id         VARCHAR(20)   NOT NULL,
	concept_class_id  VARCHAR(20)   NOT NULL,
	concept_code      VARCHAR(50)   NOT NULL,
  valid_start_date  DATE          NULL,
  valid_end_date    DATE          NOT NULL
);

INSERT INTO #derived (
	item_number,
	item_name,
	item_data_type,
	section,
	xml_naaccr_id,
	xml_parent_id,
	date_created,
	date_modified,
  year_retired,
	vocabulary_id,
	domain_id,
	concept_class_id,
	concept_code,
	valid_start_date,
	valid_end_date
)
SELECT
	i.item_number,
	i.item_name,
	i.item_data_type,
	i.section,
	i.xml_naaccr_id,
	i.xml_parent_id,
	i.date_created,
	i.date_modified,
  i.year_retired,
	LEFT(REPLACE(REPLACE(REPLACE(REPLACE(UPPER(i.section), ' ', '_'), '-', '_'), '/', '_'), '.', '_'), 20) AS vocabulary_id,
	LEFT(REPLACE(REPLACE(REPLACE(REPLACE(UPPER(i.item_data_type), ' ', '_'), '-', '_'), '/', '_'), '.', '_'), 20) AS domain_id,
	LEFT(REPLACE(REPLACE(REPLACE(REPLACE(UPPER(CONCAT(i.section, '_', COALESCE(NULLIF(i.xml_parent_id, N''), N'PARENT'))), ' ', '_'), '-', '_'), '/', '_'), '.', '_'), 20) AS concept_class_id,
	LEFT(COALESCE(NULLIF(i.xml_naaccr_id, N''), NULLIF(i.item_number, N'')), 50) AS concept_code,
  TRY_CONVERT(DATE, i.date_created) AS valid_start_date,
  CASE
    WHEN TRY_CONVERT(INT, i.year_retired) IS NULL THEN CONVERT(DATE, '2099-12-31')
    ELSE DATEFROMPARTS(TRY_CONVERT(INT, i.year_retired), 12, 31)
  END AS valid_end_date
FROM #items AS i;

IF EXISTS (SELECT 1 FROM #derived WHERE LTRIM(RTRIM(concept_code)) = N'')
BEGIN
	THROW 50000, 'Each item must include xml_naaccr_id or item_number (used to derive concept_code).', 1;
END;

DECLARE @maxMetaConceptId INT;

SELECT @maxMetaConceptId = ISNULL(MAX(x.max_id), 0)
FROM (
	SELECT MAX(vocabulary_concept_id) AS max_id FROM dbo.VOCABULARY
	UNION ALL
	SELECT MAX(domain_concept_id) AS max_id FROM dbo.DOMAIN
	UNION ALL
	SELECT MAX(concept_class_concept_id) AS max_id FROM dbo.CONCEPT_CLASS
) x;

IF OBJECT_ID('tempdb..#missing_vocab') IS NOT NULL DROP TABLE #missing_vocab;
SELECT DISTINCT
	d.vocabulary_id,
	vocabulary_name = LEFT(CONCAT('Derived from section: ', d.vocabulary_id), 255)
INTO #missing_vocab
FROM #derived d
LEFT JOIN dbo.VOCABULARY v ON v.vocabulary_id = d.vocabulary_id
WHERE v.vocabulary_id IS NULL;

IF OBJECT_ID('tempdb..#missing_domain') IS NOT NULL DROP TABLE #missing_domain;
SELECT DISTINCT
	d.domain_id,
	domain_name = LEFT(CONCAT('Derived from type: ', d.domain_id), 255)
INTO #missing_domain
FROM #derived d
LEFT JOIN dbo.DOMAIN x ON x.domain_id = d.domain_id
WHERE x.domain_id IS NULL;

IF OBJECT_ID('tempdb..#missing_class') IS NOT NULL DROP TABLE #missing_class;
SELECT DISTINCT
	d.concept_class_id,
	concept_class_name = LEFT(CONCAT('Derived: ', d.concept_class_id), 255)
INTO #missing_class
FROM #derived d
LEFT JOIN dbo.CONCEPT_CLASS c ON c.concept_class_id = d.concept_class_id
WHERE c.concept_class_id IS NULL;

;WITH numbered AS (
	SELECT vocabulary_id, vocabulary_name, rn = ROW_NUMBER() OVER (ORDER BY vocabulary_id)
	FROM #missing_vocab
)
INSERT INTO dbo.VOCABULARY (vocabulary_id, vocabulary_name, vocabulary_reference, vocabulary_version, vocabulary_concept_id)
SELECT n.vocabulary_id, n.vocabulary_name, NULL, NULL, @maxMetaConceptId + n.rn
FROM numbered n;

;WITH desired AS (
  SELECT DISTINCT
    d.vocabulary_id,
    vocabulary_name = LEFT(CONCAT('Derived from section: ', d.vocabulary_id), 255)
  FROM #derived d
)
UPDATE v
SET v.vocabulary_name = d.vocabulary_name
FROM dbo.VOCABULARY v
JOIN desired d ON d.vocabulary_id = v.vocabulary_id
WHERE ISNULL(v.vocabulary_name, N'') <> d.vocabulary_name;

SELECT @maxMetaConceptId = @maxMetaConceptId + ISNULL((SELECT COUNT(*) FROM #missing_vocab), 0);

;WITH numbered AS (
	SELECT domain_id, domain_name, rn = ROW_NUMBER() OVER (ORDER BY domain_id)
	FROM #missing_domain
)
INSERT INTO dbo.DOMAIN (domain_id, domain_name, domain_concept_id)
SELECT n.domain_id, n.domain_name, @maxMetaConceptId + n.rn
FROM numbered n;

;WITH desired AS (
  SELECT DISTINCT
    d.domain_id,
    domain_name = LEFT(CONCAT('Derived from type: ', d.domain_id), 255)
  FROM #derived d
)
UPDATE x
SET x.domain_name = d.domain_name
FROM dbo.DOMAIN x
JOIN desired d ON d.domain_id = x.domain_id
WHERE ISNULL(x.domain_name, N'') <> d.domain_name;

SELECT @maxMetaConceptId = @maxMetaConceptId + ISNULL((SELECT COUNT(*) FROM #missing_domain), 0);

;WITH numbered AS (
	SELECT concept_class_id, concept_class_name, rn = ROW_NUMBER() OVER (ORDER BY concept_class_id)
	FROM #missing_class
)
INSERT INTO dbo.CONCEPT_CLASS (concept_class_id, concept_class_name, concept_class_concept_id)
SELECT n.concept_class_id, n.concept_class_name, @maxMetaConceptId + n.rn
FROM numbered n;

;WITH desired AS (
  SELECT DISTINCT
    d.concept_class_id,
    concept_class_name = LEFT(CONCAT('Derived: ', d.concept_class_id), 255)
  FROM #derived d
)
UPDATE c
SET c.concept_class_name = d.concept_class_name
FROM dbo.CONCEPT_CLASS c
JOIN desired d ON d.concept_class_id = c.concept_class_id
WHERE ISNULL(c.concept_class_name, N'') <> d.concept_class_name;

DECLARE @baseConceptId INT;
SELECT @baseConceptId = ISNULL(MAX(concept_id), 0)
FROM dbo.CONCEPT WITH (UPDLOCK, HOLDLOCK);

IF OBJECT_ID('tempdb..#concept_stage') IS NOT NULL DROP TABLE #concept_stage;
CREATE TABLE #concept_stage (
	concept_code       VARCHAR(50)  NOT NULL,
	vocabulary_id      VARCHAR(20)  NOT NULL,
	concept_id         INT          NOT NULL,
	concept_name       VARCHAR(255) NOT NULL,
	domain_id          VARCHAR(20)  NOT NULL,
	concept_class_id   VARCHAR(20)  NOT NULL,
  valid_start_date   DATE         NULL,
  valid_end_date     DATE         NULL
);

;WITH candidates AS (
	SELECT d.*, existing_concept_id = c.concept_id, numeric_item_number = TRY_CONVERT(INT, d.item_number)
	FROM #derived d
	LEFT JOIN dbo.CONCEPT c
		ON c.concept_code = d.concept_code
	 AND c.vocabulary_id = d.vocabulary_id
),
new_only AS (
	SELECT
		c.*,
		can_use_numeric = CASE
			WHEN c.existing_concept_id IS NOT NULL THEN 0
			WHEN c.numeric_item_number IS NULL THEN 0
			WHEN EXISTS (SELECT 1 FROM dbo.CONCEPT x WHERE x.concept_id = c.numeric_item_number) THEN 0
			ELSE 1
		END
	FROM candidates c
),
assigned AS (
	SELECT
		n.concept_code,
		n.vocabulary_id,
		concept_id = COALESCE(
			n.existing_concept_id,
			CASE WHEN n.can_use_numeric = 1 THEN n.numeric_item_number END,
			@baseConceptId + ROW_NUMBER() OVER (ORDER BY n.concept_code, n.vocabulary_id)
		),
		concept_name = LEFT(n.item_name, 255),
		domain_id = n.domain_id,
		concept_class_id = n.concept_class_id,
		valid_start_date = n.valid_start_date,
    valid_end_date = CASE
      WHEN n.valid_end_date IS NOT NULL
       AND n.valid_start_date IS NOT NULL
       AND n.valid_end_date < n.valid_start_date THEN n.valid_start_date
      ELSE n.valid_end_date
    END
	FROM new_only n
)
INSERT INTO #concept_stage (
	concept_code,
	vocabulary_id,
	concept_id,
	concept_name,
	domain_id,
	concept_class_id,
	valid_start_date,
	valid_end_date
)
SELECT
	a.concept_code,
	a.vocabulary_id,
	a.concept_id,
	a.concept_name,
	a.domain_id,
	a.concept_class_id,
	a.valid_start_date,
	a.valid_end_date
FROM assigned a;

MERGE dbo.CONCEPT AS tgt
USING #concept_stage AS src
	ON tgt.concept_code = src.concept_code
 AND tgt.vocabulary_id = src.vocabulary_id
WHEN MATCHED THEN
	UPDATE SET
		tgt.concept_name = src.concept_name,
		tgt.domain_id = src.domain_id,
		tgt.concept_class_id = src.concept_class_id,
		tgt.standard_concept = NULL,
		tgt.valid_start_date = src.valid_start_date,
		tgt.valid_end_date = src.valid_end_date,
		tgt.invalid_reason = NULL
WHEN NOT MATCHED BY TARGET THEN
	INSERT (
		concept_id,
		concept_name,
		domain_id,
		vocabulary_id,
		concept_class_id,
		standard_concept,
		concept_code,
		valid_start_date,
		valid_end_date,
		invalid_reason
	)
	VALUES (
		src.concept_id,
		src.concept_name,
		src.domain_id,
		src.vocabulary_id,
		src.concept_class_id,
		NULL,
		src.concept_code,
		src.valid_start_date,
		src.valid_end_date,
		NULL
	);

COMMIT TRANSACTION;

SELECT inserted_concepts = COUNT(*)
FROM #concept_stage;